        ["2026-04-28-hotfixes-april-27-2026-c95f9c9047"] = {
            id = "2026-04-28-hotfixes-april-27-2026-c95f9c9047",
            post_key = "c95f9c9047",
            title = "Hotfixes: April 27, 2026",
            category = "Blogs (US)",
            timestamp = 1777339545,
            url = "https://news.blizzard.com/en-us/article/24276957/hotfixes-april-24-2026",
            content = {
            { type = "p", text = "Here you'll find a list of hotfixes that address various issues related to World of Warcraft: Midnight, Mists of Pandaria Classic, Season of Discovery, Burning Crusade Classic, WoW Classic Era, and Hardcore. Some of the hotfixes below take effect the moment they were implemented, while others may require scheduled realm restarts to go into effect. Please keep in mind that some issues cannot be addressed without a client-side patch update. This list will be updated as additional hotfixes are applied." },
            { type = "h2", text = "HOTFIXES" },
            { type = "hr" },
            { type = "h3", text = "April 27, 2026" },
            { type = "h3", text = "Classes" },
            { type = "list_item", text = "Demon Hunter", level = 0 },
            { type = "list_item", text = "Havok", level = 1 },
            { type = "list_item", text = "Fixed an issue that allowed Havoc to benefit from Vengeance's Annihilator talent Meteoric Rise when using Collective Anguish in specific conditions.", level = 2 },
            { type = "list_item", text = "Vengeance", level = 1 },
            { type = "list_item", text = "Annihilator: Fixed an issue that caused Celestial Echoes to grant 5 additional Fury per Fracture instead of the intended 3 Fury.", level = 2 },
            { type = "list_item", text = "Evoker", level = 0 },
            { type = "list_item", text = "Fixed an issue where Renewing Blaze would not always trigger its healing effect from certain attacks.", level = 1 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "Frost", level = 1 },
            { type = "list_item", text = "Fixed an issue causing Hand of Frost Rank 2 to not provide the correct percent chance increase per stack of Shatter.", level = 2 },
            { type = "list_item", text = "Fixed an issue that could cause Flurry to not benefit fully from the damage bonus of Brain Freeze, when a non-Brain-Freeze-affected Flurry was cast immediately afterwards.", level = 2 },
            { type = "list_item", text = "Fixed an issue causing some Tracked Buffs for Frostfire to not display correctly.", level = 2 },
            { type = "list_item", text = "Casting Mass Invisibility now correctly interrupts the Mage's current spell.", level = 2 },
            { type = "list_item", text = "Monk", level = 0 },
            { type = "list_item", text = "Windwalker", level = 1 },
            { type = "list_item", text = "Touch of Karma now shows as a large defensive buff on raid frames.", level = 2 },
            { type = "list_item", text = "Rogue", level = 0 },
            { type = "list_item", text = "Trickster: Cloud Cover's visual effect is now only visible to the caster in all circumstances.", level = 1 },
            { type = "list_item", text = "Assassination", level = 1 },
            { type = "list_item", text = "Separated the tracked buffs for Implacable into two elements so they can be tracked separately with the Cooldown Manager.", level = 2 },
            { type = "list_item", text = "Duration of increased Energy generation.", level = 3 },
            { type = "list_item", text = "Amount of Energy regeneration you'll receive when Envenom expires.", level = 3 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Affliction", level = 1 },
            { type = "list_item", text = "Fixed an issue where Shared Agony would not function after casting a Curse.", level = 2 },
            { type = "list_item", text = "Hellcaller: Fixed an issue where Xalan's Cruelty would not increase the critical strike chance of Wrath of Nathreza.", level = 2 },
            { type = "list_item", text = "Fixed an issue where periodic damage caused by Malefic Grasp is unaffected by Death's Embrace.", level = 2 },
            { type = "list_item", text = "Soul Harvester: Fixed an issue where consuming Nightfall with Malefic Grasp would not activate Wicked Reaping.", level = 2 },
            { type = "list_item", text = "Demonology", level = 1 },
            { type = "list_item", text = "Fixed an issue where Fel Armaments would reduce the cooldown of Felstorm by 20 seconds, rather than the intended 10 seconds.", level = 2 },
            { type = "h3", text = "Delves" },
            { type = "list_item", text = "The Darkway", level = 0 },
            { type = "list_item", text = "Corrupted Leyline will no longer sometimes continue to cast Detected! after it’s out of range.", level = 1 },
            { type = "list_item", text = "The Shadow Enclave", level = 0 },
            { type = "list_item", text = "Fixed an issue where characters could lose the ability to strafe after picking up a mirror.", level = 1 },
            { type = "h3", text = "Items and Rewards" },
            { type = "list_item", text = "Fixed a Great Vault display bug where the World Row indicated an item level of 272 for the Tier 5 Ritual Site, instead of the intended 269 item level.", level = 0 },
            { type = "h3", text = "Player versus Player" },
            { type = "list_item", text = "Demon Hunter", level = 0 },
            { type = "list_item", text = "Fixed an issue that prevented the target throw effect from being available while using Illidan's Grasp.", level = 1 },
            { type = "list_item", text = "Havoc", level = 1 },
            { type = "list_item", text = "Fixed an issue that caused Consume Magic to remove an additional Magic effect from the primary target when the Blood Moon PvP Talent was selected.", level = 2 },
            { type = "h3", text = "Quests" },
            { type = "list_item", text = "Resolved an issue where players who completed the quest \"The Legend of Aln'Sharan\" could not gather them on alts without completing the quest first.", level = 0 },
            { type = "hr" },
            { type = "h3", text = "April 24, 2026" },
            { type = "h3", text = "Achievements" },
            { type = "list_item", text = "Midnight Keystone Myth - Season One is now available to players who attained a Mythic+ Rating of at least 3400 during Midnight Season 1.", level = 0 },
            { type = "h3", text = "Characters" },
            { type = "list_item", text = "Pandaren characters who boost during the intro sequence will now be able to port to their houses.", level = 0 },
            { type = "h3", text = "Classes" },
            { type = "list_item", text = "Death Knight", level = 0 },
            { type = "list_item", text = "Unholy", level = 1 },
            { type = "list_item", text = "Festering Scythe is now an aura on the player, resolving issues that occur when extending the duration of plagues.", level = 2 },
            { type = "dev_note", text = "The underlying issue here was proving to be problematic for a number of reasons and we felt like this would be the safest approach for now.", level = 3 },
            { type = "list_item", text = "Resolved an issue causing Magus of the Dead to not take action immediately on spawn.", level = 2 },
            { type = "list_item", text = "Resolved an issue causing Forbidden Knowledge Rank 4 to activate less than stated.", level = 2 },
            { type = "list_item", text = "Resolved an issue causing Unholy Devotion to grant Haste in addition to attack speed and energy regeneration.", level = 2 },
            { type = "list_item", text = "Disease Cloud is now cast by the Abomination, resolving issues such as it not interacting with pet scaling talents.", level = 2 },
            { type = "list_item", text = "Demon Hunter", level = 0 },
            { type = "list_item", text = "Devourer", level = 1 },
            { type = "list_item", text = "Fixed an issue causing the Single-Button Assistant and Assisted Highlight to not recommend Collapsing Star outside of melee range.", level = 2 },
            { type = "list_item", text = "Vengeance", level = 1 },
            { type = "list_item", text = "Fixed an issue that caused Metamorphosis to be put on cooldown when Last Resort's effect triggered.", level = 2 },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Marksmanship", level = 1 },
            { type = "list_item", text = "Corrected an issue where Unbreakable Bond could give the damage reduction effect to the hunter rather than their pet.", level = 2 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "Frost", level = 1 },
            { type = "list_item", text = "Fixed an issue causing Hand of Frost (Rank 2) to not provide the correct percent chance increase per stack of Shatter.", level = 2 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "Holy", level = 1 },
            { type = "list_item", text = "Fixed an issue that caused Holy Armaments to significantly impact framerates.", level = 2 },
            { type = "list_item", text = "Priest", level = 0 },
            { type = "list_item", text = "Shadow", level = 1 },
            { type = "list_item", text = "Voidweaver: Fixed an issue causing Overwhelming Shadows to increase the damage of Mind Blast.", level = 2 },
            { type = "list_item", text = "Rogue", level = 0 },
            { type = "list_item", text = "Trickster: Fixed an issue that caused Cloud Cover's effect to cost 30 Energy to activate.", level = 1 },
            { type = "list_item", text = "Trickster: Cloud Cover's visual effect is now only visible to the caster in all circumstances.", level = 1 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Affliction", level = 1 },
            { type = "list_item", text = "Fixed an issue where Jinx would not function if Foul Mouth was not talented.", level = 2 },
            { type = "list_item", text = "Demonology", level = 1 },
            { type = "list_item", text = "Fixed an issue where Demonic Gateway would benefit Hellbent Commander.", level = 2 },
            { type = "h3", text = "Delves" },
            { type = "list_item", text = "Valeera is no longer unwilling to attack Poison Dart Frog or Giant Cursed Bullfrog.", level = 0 },
            { type = "list_item", text = "Atal’Aman", level = 0 },
            { type = "list_item", text = "Adjusted the placement of several out-of-range Sanctified Banners in two story variants.", level = 1 },
            { type = "list_item", text = "The Darkway", level = 0 },
            { type = "list_item", text = "The Corrupted Leyline will no longer sometimes continue to cast Detected! after being out of its range.", level = 1 },
            { type = "h3", text = "Dungeons and Raids" },
            { type = "list_item", text = "Maisara Caverns", level = 0 },
            { type = "list_item", text = "Addressed an issue where players could remain in combat after defeating Vordaza.", level = 1 },
            { type = "h3", text = "Housing" },
            { type = "list_item", text = "Decorative Dornogal Opals (small, medium and large) are now available for purchase from the Disguised Decor Duel Vendor in Silvermoon.", level = 0 },
            { type = "h3", text = "Player versus Player" },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Marksmanship", level = 1 },
            { type = "list_item", text = "Precise Shots now benefits Kill Shot and Black Arrow at 50% effectiveness in PvP combat.", level = 2 },
            { type = "list_item", text = "Black Arrow damage reduced by 30% in PvP combat.", level = 2 },
            { type = "list_item", text = "All damage reduced by 10% in PvP combat.", level = 2 },
            { type = "dev_note", text = "Several talent changes in 12.0.5 led to Marksmanship overperforming in PvP. These updates target changes to Black Arrow and their overall damage to account for the new interactions and reduce their effectiveness at both burst damage and overall pressure.", level = 3 },
            { type = "list_item", text = "Mage", level = 0 },
