        ["2026-04-25-bonus-rolls-what-happened-and-next-steps-b5a982f679"] = {
            id = "2026-04-25-bonus-rolls-what-happened-and-next-steps-b5a982f679",
            post_key = "b5a982f679",
            title = "Bonus Rolls – What Happened and Next Steps",
            category = "General Discussion (US)",
            timestamp = 1777110078,
            url = "https://us.forums.blizzard.com/en/wow/t/2296587/1",
            content = {
            { type = "p", text = "Hello!" },
            { type = "p", text = "We want to follow up on our previous post about issues we encountered with the new Voidforge bonus roll system. The Voidforge system is a brand new system using new tech that enables players to earn their desired myth track gear utilizing a bonus roll currency called Nebulous Voidcores to improve the player experience of gearing during Season 1 of Midnight." },
            { type = "h3", text = "What Happened?" },
            { type = "p", text = "We tested the system on our internal environment to make sure it was working as intended and fix issues, but there was a subtle bug we missed that we can now see was a result of a limitation in our internal test environment." },
            { type = "p", text = "This new bonus roll system is intended to work like this: every time you use your Nebulous Voidcore on an additional piece of endgame loot, whether in Mythic+ Dungeons, Raids, Bountiful Delves, or Prey, it saves a record of the piece of loot and checks it off a list tied to your character, so that you shouldn’t receive the same piece of loot again. After we launched 12.0.5 (and before we fixed the bug), when players queued with other players into M+ dungeons, Bountiful Delves or Raids, it was possible for the roll data to sometimes save to the wrong database, leading to duplicate rolls." },
            { type = "h3", text = "How Could That Happen?" },
            { type = "p", text = "There are some limited differences between our internal realms and the realms you play on, and one of those differences is the number of databases we use to support the live realms. Some of the databases tied to live realms hold all of your character data, and this includes the list where the bonus rolls are saved." },
            { type = "p", text = "The functionality we had in place was working as intended for internal environments, but was ultimately the wrong set up for live environments with their multitude of databases." },
            { type = "p", text = "When it became apparent that some players were occasionally receiving the same item twice, we made it a top priority to fix the issue, and we got the system working as intended on live realms at around 8:05 p.m. PDT on Wednesday, April 22 (05:05 CEST April 23)." },
            { type = "h3", text = "What’s Next?" },
            { type = "p", text = "We really want to make this right as best we can, so we’re going to refund every Nebulous Voidcore that was spent before we fixed the issue. We’re identifying every player-character who spent a Nebulous Voidcore before the fix and in the next day or so, we will grant them back to you in-game." },
            { type = "p", text = "We want to get players who were affected by the bug back on track, and we want to help players who spent their tokens before the fix to mitigate the possibility of further duplicate rolls of the loot they received." },
            { type = "h3", text = "How Can There Be Further Duplicate Rolls?" },
            { type = "p", text = "For example, let’s look at Jay the Mistweaver Monk who spent 2 Nebulous Voidcores in Pit of Saron and received Flayer’s Black Belt and Shaggy Wyrmleather Leggings through the bonus roll system before the bug was fixed. Jay’s bonus rolls may or may not have been properly checked off the list in the database prior to the fix, so the next time he goes into Pit of Saron and tries to use his bonus rolls, he may receive new items or he may receive the Belt or the Leggings again." },
            { type = "p", text = "Since the system is now working as intended, these new rolls made will be saved to the checklist properly, so duplicates of items rolled on after the fix are not possible." },
            { type = "h3", text = "What If I Didn’t Spend My Nebulous Voidcores On Bonus Rolls?" },
            { type = "p", text = "If you did not spend any of your Voidcores before the fix, any bonus roll you now make will properly be accounted for and checked off the list, and you will not be at risk for any duplicate rolls." },
            { type = "h3", text = "Thank You For Your Patience And Understanding" },
            { type = "p", text = "We apologize for all of this. While it provided us with a better understanding of a potential design pitfall that we will ensure we avoid in the future, we regret disrupting the game for you. Thank you for your passionate feedback the last couple of days. We really appreciate it." },
            },
        },
        ["2026-04-25-void-incursions-are-back-25-april-9456975169"] = {
            id = "2026-04-25-void-incursions-are-back-25-april-9456975169",
