        ["2026-04-23-bonus-roll-bug-fix-b5ac941282"] = {
            id = "2026-04-23-bonus-roll-bug-fix-b5ac941282",
            post_key = "b5ac941282",
            title = "Bonus Roll Bug Fix",
            category = "General Discussion (EU)",
            timestamp = 1776983176,
            url = "https://eu.forums.blizzard.com/en/wow/t/617011/1",
            content = {
            { type = "p", text = "With hotfixes that began rolling out a couple of hours ago and are now applicable in all instances, we’ve preliminarily addressed a bug in 12.0.5 where rolling on loot did not remove the received item from the pool for subsequent Bonus Rolls, which made it possible for players to receive the same item from a Bonus Roll." },
            { type = "p", text = "It is now safe to roll on loot. Newly rolled items will now correctly remove the item from the bonus pool." },
            { type = "p", text = "We’ll have more information to share tomorrow about this issue and the next steps we’re taking to remediate the situation for affected players." },
            { type = "p", text = "Thank you very much for your feedback and understanding." },
            },
        },
        ["2026-04-23-bonus-roll-bug-fix-5ae0e10f79"] = {
            id = "2026-04-23-bonus-roll-bug-fix-5ae0e10f79",
            post_key = "5ae0e10f79",
            title = "Bonus Roll Bug Fix",
            category = "General Discussion (US)",
            timestamp = 1776983116,
            url = "https://us.forums.blizzard.com/en/wow/t/2296109/1",
            content = {
            { type = "p", text = "With hotfixes that began rolling out a couple of hours ago and are now applicable in all instances, we’ve preliminarily addressed a bug in 12.0.5 where rolling on loot did not remove the received item from the pool for subsequent Bonus Rolls, which made it possible for players to receive the same item from a Bonus Roll." },
            { type = "p", text = "It is now safe to roll on loot. Newly rolled items will now correctly remove the item from the bonus pool." },
            { type = "p", text = "We’ll have more information to share tomorrow about this issue and the next steps we’re taking to remediate the situation for affected players." },
            { type = "p", text = "Thank you very much for your feedback and understanding." },
            },
        },
        ["2026-04-23-bonus-rolls-what-happened-and-next-steps-3f6b770b38"] = {
            id = "2026-04-23-bonus-rolls-what-happened-and-next-steps-3f6b770b38",
            post_key = "3f6b770b38",
            title = "Bonus Rolls – What Happened and Next Steps",
            category = "General Discussion (EU)",
            timestamp = 1776983002,
            url = "https://eu.forums.blizzard.com/en/wow/t/617132/1",
            content = {
            { type = "p", text = "Hello!" },
            { type = "p", text = "We want to follow up on our previous post about issues we encountered with the new Voidforge bonus roll system. The Voidforge system is a brand new system using new tech that enables players to earn their desired myth track gear utilizing a bonus roll currency called Nebulous Voidcores to improve the player experience of gearing during Season 1 of Midnight." },
            { type = "h3", text = "What Happened?" },
            { type = "p", text = "We tested the system on our internal environment to make sure it was working as intended and fix issues, but there was a subtle bug we missed that we can now see was a result of a limitation in our internal test environment." },
            { type = "p", text = "This new bonus roll system is intended to work like this: every time you use your Nebulous Voidcore on an additional piece of endgame loot, whether in Mythic+ Dungeons, Raids, Bountiful Delves, or Prey, it saves a record of the piece of loot and checks it off a list tied to your character, so that you shouldn’t receive the same piece of loot again. After we launched 12.0.5 (and before we fixed the bug), when players queued with other players into M+ dungeons, Bountiful Delves or Raids, it was possible for the roll data to sometimes save to the wrong database, leading to duplicate rolls." },
            { type = "h3", text = "How Could That Happen?" },
            { type = "p", text = "There are some limited differences between our internal realms and the realms you play on, and one of those differences is the number of databases we use to support the live realms. Some of the databases tied to live realms hold all of your character data, and this includes the list where the bonus rolls are saved." },
            { type = "p", text = "The functionality we had in place was working as intended for internal environments, but was ultimately the wrong set up for live environments with their multitude of databases." },
            { type = "p", text = "When it became apparent that some players were occasionally receiving the same item twice, we made it a top priority to fix the issue, and we got the system working as intended on live realms at around 8:05 p.m. PDT on Wednesday, April 22 (05:05 CEST April 23)." },
            { type = "h3", text = "What’s Next?" },
            { type = "p", text = "We really want to make this right as best we can, so we’re going to refund every Nebulous Voidcore that was spent before we fixed the issue. We’re identifying every player-character who spent a Nebulous Voidcore before the fix and in the next day or so, we will grant them back to you in-game." },
            { type = "p", text = "We want to get players who were affected by the bug back on track, and we want to help players who spent their tokens before the fix to mitigate the possibility of further duplicate rolls of the loot they received." },
            { type = "h3", text = "How Can There Be Further Duplicate Rolls?" },
            { type = "p", text = "For example, let’s look at Jay the Mistweaver Monk who spent 2 Nebulous Voidcores in Pit of Saron and received Flayer’s Black Belt and Shaggy Wyrmleather Leggings through the bonus roll system before the bug was fixed. Jay’s bonus rolls may or may not have been properly checked off the list in the database prior to the fix, so the next time he goes into Pit of Saron and tries to use his bonus rolls, he may receive new items or he may receive the Belt or the Leggings again." },
            { type = "p", text = "Since the system is now working as intended, these new rolls made will be saved to the checklist properly, so duplicates of items rolled on after the fix are not possible." },
            { type = "h3", text = "What If I Didn’t Spend My Nebulous Voidcores On Bonus Rolls?" },
            { type = "p", text = "If you did not spend any of your Voidcores before the fix, any bonus roll you now make will properly be accounted for and checked off the list, and you will not be at risk for any duplicate rolls." },
            { type = "h3", text = "Thank You For Your Patience And Understanding" },
            { type = "p", text = "We apologize for all of this. While it provided us with a better understanding of a potential design pitfall that we will ensure we avoid in the future, we regret disrupting the game for you. Thank you for your passionate feedback the last couple of days. We really appreciate it." },
            },
        },
        ["2026-04-22-housing-temporarily-disabled-in-this-region-enabled-at-730-am-pdt-apri-ef592da93d"] = {
            id = "2026-04-22-housing-temporarily-disabled-in-this-region-enabled-at-730-am-pdt-apri-ef592da93d",
            post_key = "ef592da93d",
            title = "Housing Temporarily Disabled in this Region - Enabled at 7:30 a.m. PDT April 22",
            category = "General Discussion (US)",
            timestamp = 1776880637,
            url = "https://us.forums.blizzard.com/en/wow/t/2294724/1",
            content = {
            { type = "p", text = "During our routine testing with realms offline to deploy the new patch, we discovered a critical bug in Housing that would cause unacceptable errors for some players." },
            { type = "p", text = "Fixing this bug is a top priority for us, and while we work on it, we’ve decided to open realms on patch 12.0.5 with Housing and Neighborhoods disabled in this region (The Americas and Oceania)." },
            { type = "p", text = "Once we have a fix developed and tested, we will perform an additional brief maintenance in this region to bring Housing back online for everyone." },
            { type = "p", text = "Thank you very much for your patience and understanding." },
            },
        },
        ["2026-04-22-price-update-on-subscription-options-and-game-time-for-world-of-warcra-256a2e2a93"] = {
            id = "2026-04-22-price-update-on-subscription-options-and-game-time-for-world-of-warcra-256a2e2a93",
            post_key = "256a2e2a93",
            title = "Price Update on Subscription Options and Game Time for World of Warcraft",
            category = "General Discussion (EU)",
            timestamp = 1776879797,
            url = "https://eu.forums.blizzard.com/en/wow/t/616941/1",
            content = {
            { type = "p", text = "World of Warcraft is played in many regions around the world, and we regularly conduct reviews of the prices of our games and services in all currencies. From time to time, it’s necessary to make changes to certain pricing based on a variety of factors, including global and regional market conditions." },
            { type = "p", text = "As a result of our review, on June 22, 2026, the pricing for recurring subscription plans inUnited Kingdom, Kazakhstan, and Georgia will be adjusted as follows:" },
            { type = "p", text = "Furthermore, the Turkish Lira (TRY) will be changed to euro (EUR) in Battle.net. The pricing for recurring subscription plans inTurkey will be adjusted as follows:" },
            { type = "p", text = "For the non-recurring 60-Days game time option and price adjustments on other services which include pets, mounts, tokens, and game services please come back and visit this post closer to the June 22 date." },
            { type = "p", text = "Current prices will remain in effect until June 22, 2026. You will not be charged the new price until your next billing occurrence after this date and time. To take advantage of current pricing, we strongly suggest making your purchase selection by June 22, 2026, before the new pricing goes into effect." },
            { type = "p", text = "We know that people have a lot of options for entertainment, and we do not take pricing adjustments lightly. We appreciate that players choose to spend their time with World of Warcraft, and we are committed to ensuring the game continues to provide our players with great entertainment value." },
            { type = "p", text = "You can review your World of Warcraft subscription options and payment methods at any time through Battle.net Account Management or Battle.net Shop." },
            { type = "p", text = "Thank you," },
            { type = "p", text = "The World of Warcraft Team" },
            },
        },
        ["2026-04-22-the-1205-content-update-now-live-e4ec5b2dba"] = {
            id = "2026-04-22-the-1205-content-update-now-live-e4ec5b2dba",
            post_key = "e4ec5b2dba",
            title = "The 12.0.5 Content Update Now Live!",
            category = "Blogs (EU)",
            timestamp = 1776872360,
            url = "https://news.blizzard.com/en-gb/article/24266871/the-12-0-5-content-update-now-live",
            content = {
            { type = "p", text = "Engage in new activities, experience more of the story in Midnight, and earn more loot as the efforts to push back the forces of the Void and their agents continue. You’ll undertake new Void Assaults, disrupt powerful Ritual Sites, get a boost with Voidforge, group up for Decor Duels, and more." },
            { type = "hr" },
            { type = "h2", text = "STAVE OFF VOID ASSAULTS" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-04-22-the-1205-content-update-now-live-e4ec5b2dba\\image-1.jpg" },
            { type = "p", text = "The forces of the Void are vying for position and control amongst themselves in a bid for more power. As they seek every opportunity they can, attacks begin in the Eversong Woods and Zul’Aman zones. [Learn More]" },
            { type = "h3", text = "Void Strike" },
            { type = "list_item", text = "Void Strikes take part in Eversong Woods or Zul’Aman on a weekly rotation. Once completed, a new one will begin in another part of the zone and continue to rotate through the zones.", level = 0 },
            { type = "h3", text = "Void Incursion" },
            { type = "list_item", text = "These larger scenarios occur when enough Void Strikes have been completed in the zones and will take the might of many of Azeroth’s champions to defeat them.", level = 0 },
            { type = "hr" },
            { type = "h2", text = "DISRUPT RITUAL SITES" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-04-22-the-1205-content-update-now-live-e4ec5b2dba\\image-2.jpg" },
            { type = "p", text = "Put a stop to rituals meant to empower the ambitions of power-hungry naga and Twilight’s Blade cultists in small one to five player instances. As you take on greater challenges, you’ll be able to receive greater rewards." },
            { type = "p", text = "In Ritual Sites, you’ll choose some of the challenges you’ll face as you climb through the tiers. Players will also unlock Great Vault rewards for the World content row alongside Delves and Prey." },
            { type = "p", text = "Players will earn Field Accolades from both Void Assaults and Ritual Sites as currency they can use to purchase Champion and Heroic quality gear and rewards. [Learn More]" },
            { type = "hr" },
            { type = "h2", text = "GET A LEG UP WITH THE VOIDFORGE" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-04-22-the-1205-content-update-now-live-e4ec5b2dba\\image-3.jpg" },
            { type = "p", text = "Voidforge will provide new opportunities for players in Midnight to take their game further. You’ll help aid domanaar Decimus build a Voidforge to begin transmuting Nebulous Voidcores, which are transmutable into powerful equipment upon defeating powerful foes in Midnight Season 1 raids or completing Mythic+ dungeons, and Bountiful Delves and Prey Hunts on Nightmare difficulty." },
            { type = "p", text = "After unlocking the Voidforge, Decimus will require additional assistance to craft the Ascendant Nilhammer, allowing players to upgrade their weapons and trinkets to new heights by collecting Ascendant Voidcores. [Learn More]" },
            { type = "hr" },
            { type = "h2", text = "HIDE OR SEEK WITH DECOR DUELS" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-04-22-the-1205-content-update-now-live-e4ec5b2dba\\image-4.jpg" },
            { type = "p", text = "Amidst all the danger that swirls above Azeroth, there’s something to be said about having a little fun. Players can join in a team vs team hide-and-seek style game taking place in Silvermoon City through the Group Finder Tool (PvP tab) to either hide as various Housing decor items or seek out those who have donned the guise of an item. You’ll earn new rewards, including a mount, toys, and Housing decor, through this bite-sized event. [Learn More]" },
            { type = "hr" },
            { type = "h2", text = "NEW ACTIVITY: ABYSS ANGLERS" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-04-22-the-1205-content-update-now-live-e4ec5b2dba\\image-5.jpg" },
            { type = "p", text = "Dive deep into the shimmering waters off Zul'Aman's rugged coast, where schools of exotic fish swarm just beneath the surface in a new repeatable event—Abyss Anglers. Team up to spear as many as you can and rack up points to unlock fishing rewards and upgrades to your diver gear, allowing you to venture deeper into the abyss where the greatest treasures await." },
            { type = "p", text = "Seek out Depthdiver Jeju to suit up and enter the Depths. Zip through whirlpools, catch creatures with your harpoon, and discover treasures amidst the underwater steam vents." },
            { type = "p", text = "Prove your mastery to earn dive equipment upgrades and cosmetics." },
            { type = "hr" },
            { type = "h2", text = "NEW MYTHIC+DUNGEON FEATURE AND ACHIEVEMENTS" },
            { type = "h3", text = "New Feature Lindormi's Glow" },
            { type = "p", text = "Lindormi's Glow highlights select enemy forces even when the Lindormi's Guidance affix is inactive. Defeating all highlighted enemies will complete the enemy forces requirement for a Keystone Dungeon." },
            { type = "list_item", text = "Any player whose class supports a tank role specialization can choose to use Lindormi's Glow by speaking with Lindormi near the The Timeways portal or at the end of a Keystone Dungeon.", level = 0 },
            { type = "list_item", text = "Lindormi's Glow will activate in a Keystone Dungeon if the party's tank has chosen to use this feature.", level = 0 },
            { type = "list_item", text = "Players can disable Lindormi's Glow by speaking with Lindormi again.", level = 0 },
            { type = "h3", text = "New Achievements" },
            { type = "p", text = "Midnight Keystone Myth: Season One – Attain a Mythic+ Rating of at least 3400 during Midnight Season 1. Rewards a Timelost Saddle that can be exchanged with Lindormi for a mount of your choice. Mounts include: A variety of new mounts, and Keystone Master and Keystone Legend mounts from previous seasons." },
            { type = "p", text = "Umbral Champion: Midnight Season One – End Midnight Mythic+ Season 1 with a Mythic+ Rating in the top 1% of all players in your region. Rewards a new exclusive mount." },
            { type = "hr" },
            { type = "h2", text = "12.0.5 CONTENT NOTES" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-04-22-the-1205-content-update-now-live-e4ec5b2dba\\image-6.jpg" },
            { type = "p", text = "Learn more about all the changes in our content update notes." },
            { type = "hr" },
            { type = "p", text = "More adventures are calling you home." },
            },
        },
        ["2026-04-22-mobilize-your-allies-and-thwart-incoming-void-assaults-db9d1ae589"] = {
            id = "2026-04-22-mobilize-your-allies-and-thwart-incoming-void-assaults-db9d1ae589",
            post_key = "db9d1ae589",
            title = "Mobilize Your Allies and Thwart Incoming Void Assaults",
            category = "Blogs (EU)",
            timestamp = 1776867651,
            url = "https://news.blizzard.com/en-gb/article/24266324/mobilize-your-allies-and-thwart-incoming-void-assaults",
            content = {
            { type = "p", text = "The forces of the Void are vying for position and control amongst themselves in a grasp for more power. As they seek every opportunity they can, attacks begin in the Eversong Woods and Zul’Aman zones. Succeed in putting a stop to them, and you reap new rewards." },
            { type = "hr" },
            { type = "h2", text = "PUT A STOP TO VOID STRIKES" },
            { type = "p", text = "Void Strikes take part in Eversong Woods or Zul’Aman on a weekly rotation. Once completed, a new one will begin in another part of the zone and continue to rotate through the zone as they are completed." },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-04-22-mobilize-your-allies-and-thwart-incoming-void-assaults-db9d1ae589\\image-1.jpg" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-04-22-mobilize-your-allies-and-thwart-incoming-void-assaults-db9d1ae589\\image-2.jpg" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-04-22-mobilize-your-allies-and-thwart-incoming-void-assaults-db9d1ae589\\image-3.jpg" },
            { type = "p", text = "Completing Void Strikes provides a Field Pouch with each completion containing Field Accolades, gold, Voidlight Marl, and more, acknowledging your acumen in the field." },
            { type = "hr" },
            { type = "h2", text = "BRACE FOR THE VOID INCURSION" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-04-22-mobilize-your-allies-and-thwart-incoming-void-assaults-db9d1ae589\\image-4.jpg" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-04-22-mobilize-your-allies-and-thwart-incoming-void-assaults-db9d1ae589\\image-5.jpg" },
            { type = "p", text = "Void Incursions occur when enough Void Strikes have been completed in the zone in which they are active. A progress bar will show on the map allowing you to track when it begins. Gather your allies and head to the gates of Silvermoon City in Eversong Woods or Speaker's Rest in Zul'Aman to take part, as it will take the might of many of Azeroth’s champions to defeat them." },
            { type = "hr" },
            { type = "h2", text = "A QUEST!" },
            { type = "p", text = "Ranger Captain Lilatha and Kul’amara the Fierce located on the second floor of The Bazaar will also have quests for you to complete rewarding a Ranger’s Cache for completion." },
            { type = "p", text = "“Cache containing Field Accolades, Relic Coffer Key shards, materials for upgrading gear, gold, and more.”" },
            { type = "hr" },
            { type = "h2", text = "REAP YOUR REWARDS" },
            { type = "p", text = "When the dust settles and you’ve collected your just rewards, head back to the second level of The Bazaar in Silvermoon City to purchase a variety of items with your Field Accolades and Voidlight Marl. You can purchase new Housing Decor, armor appearances, Heroic and Champion level items, mounts, and more. Visit the Ritual Sites article to see the full list of vendor items." },
            { type = "hr" },
            { type = "p", text = "Whether you’re working on your first character or an alternate character, Void Assaults offer a way to get up to speed and get into the action in Midnight." },
            },
        },
        ["2026-04-22-wow-bcc-anniversary-edition-overlords-of-outland-arrives-14-may-10952c8ddf"] = {
            id = "2026-04-22-wow-bcc-anniversary-edition-overlords-of-outland-arrives-14-may-10952c8ddf",
            post_key = "10952c8ddf",
            title = "WoW BCC Anniversary Edition: Overlords of Outland Arrives 14 May",
            category = "Blogs (EU)",
            timestamp = 1776867648,
            url = "https://news.blizzard.com/en-gb/article/24272608/wow-bcc-anniversary-edition-overlords-of-outland-arrives-14-may",
            content = {
            { type = "p", text = "The battle for Outland heats up on 14 May as WoW Burning Crusade Classic Anniversary Edition: Overlords of Outland launches globally on all realms at 23:00 BST." },
            { type = "p", text = "Take the fight to Illidan Stormrage’s lieutenants, brave two new raids, and chase new rewards across the shattered world of Outland." },
            { type = "list_item", text = "Two New Raids: The Eye and Serpentshrine Cavern", level = 0 },
            { type = "list_item", text = "New Reputation Factions: Ogri’la and Sha’tari Skyguard", level = 0 },
            { type = "list_item", text = "Arena Season 2", level = 0 },
            { type = "list_item", text = "New Profession Recipes", level = 0 },
            { type = "list_item", text = "Druid Swift Flight Form", level = 0 },
            { type = "hr" },
            { type = "p", text = "Get ready to adventure across the shattered skies and torn lands of Outland as you continue to protect Azeroth from the threat of destruction, beginning 14 May." },
            },
        },
        ["2026-04-22-1205-ptr-development-notes-2faa464ecf"] = {
            id = "2026-04-22-1205-ptr-development-notes-2faa464ecf",
            post_key = "2faa464ecf",
            title = "12.0.5 PTR Development Notes",
            category = "12.0.5 Public Test Realm (EU)",
            timestamp = 1776867644,
            url = "https://eu.forums.blizzard.com/en/wow/t/610519/1",
            content = {
            { type = "h1", text = "12.0.5 PTR DEVELOPMENT NOTES" },
            { type = "hr" },
            { type = "h2", text = "INCOMING VOID ASSAULTS" },
            { type = "p", text = "The forces of the Void are vying for position and control amongst themselves in a bid for more power. As they seek every opportunity they can, attacks begin in the Eversong Woods and Zul’Aman zones." },
            { type = "p", text = "Void Strike" },
            { type = "p", text = "Void Strikes take part in Eversong Woods or Zul’Aman on a weekly rotation. Once completed, a new one will begin in another part of the zone and continue to rotate through the zones." },
            { type = "p", text = "Void Incursion" },
            { type = "p", text = "These larger scenarios occur when enough Void Strikes have been completed in the zones and will take the might of many of Azeroth’s champions to defeat them." },
            { type = "dev_note", text = "Zul’Aman Void Assaults are available this week and will rotate to Eversong Woods Void Assaults next week.", level = 0 },
            { type = "h2", text = "RITUAL SITES" },
            { type = "p", text = "Put a stop to rituals meant to empower the ambitions of power-hungry naga and Twilight’s Blade cultists in small one to five player instances. As you take on greater challenges, you’ll be able to receive greater rewards." },
            { type = "p", text = "In Ritual Sites, you’ll choose some of the challenges you’ll face as you climb through the tiers. Players will also unlock Great Vault rewards for the World content row alongside Delves and Prey." },
            { type = "p", text = "Players will earn Field Accolades from both Void Assaults and Ritual Sites as currency they can use to purchase Champion and Heroic quality gear and rewards." },
            { type = "dev_note", text = "Daggerspine Ritual Site is available this week and will rotate to the Broken Throne Ritual Site next week.", level = 0 },
            { type = "h2", text = "THE VOIDFORGE" },
            { type = "p", text = "As Midnight Season 1 begins, players will assist the domanaar Decimus with the construction of the Voidforge as they explore the nature of mysterious Voidcores. This progression is warband-wide. With the Voidforge’s initial completion in this content update, Decimus gains the ability to transmute Void energy into powerful Nebulous Voidcores every week that can be used to acquire additional loot every week and chase specific items over time. After players help acquire a new tool that will allow Voidforge’s power to reach new heights, Decimus will return the favor by infusing weapons and trinkets with greater power from rare Ascendant Voidcores." },
            { type = "p", text = "Nebulous Voidcores" },
            { type = "p", text = "Players can use Nebulous Voidcores to more easily obtain specific equipment whether they’re chasing best-in-slot items on their main character or looking to quickly gear up their alts later in the season." },
            { type = "p", text = "Upon defeating a Midnight Season 1 raid boss or completing a Mythic+ Dungeon, Bountiful Delve, or Prey Hunt on Nightmare difficulty, players may choose to spend their Nebulous Voidcores to receive a random item appropriate for their Loot Specialization from that activity. After receiving an item in this way, it is removed from that loot pool until all eligible items have been obtained on a per-difficulty basis. For example, receiving the Ranger-Captain’s Iridescent Insignia trinket from the Crown of the Cosmos encounter in the Voidspire on Normal difficulty will not remove it from consideration on Heroic or Mythic difficulty. The item level of Mythic+ rewards from Nebulous Voidcores is equivalent to Great Vault rewards from that Keystone level, i.e., Myth 1/6 at Keystone level +10 and above." },
            { type = "p", text = "Upon completing the Voidspire Crown of the Cosmos encounter on Normal difficulty while carrying Nebulous Voidcores, a Marksmanship Hunter would be offered the following Bonus Loot prompt:" },
            { type = "image", width = 526, height = 274, u = 0.513672, v = 0.535156, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-04-22-1205-ptr-development-notes-2faa464ecf\\image-1.jpg" },
            { type = "p", text = "Similarly, upon completing Windrunner Spire on Mythic+ Keystone level +10 or above while carrying Nebulous Voidcores, the same player would see the following:" },
            { type = "image", width = 497, height = 357, u = 0.970703, v = 0.697266, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-04-22-1205-ptr-development-notes-2faa464ecf\\image-2.jpg" },
            { type = "p", text = "Some of you may be wondering why some items are missing from these examples. This is because, despite the common misconception, not all loot is Hunter loot." },
            { type = "p", text = "Decimus will offer Nebulous Voidcores to the player in exchange for a choice of valuable resources including gold, Voidlight Marl, and Veteran Dawncrests. The total number of Nebulous Voidcores available to a character increases by two every week for the remainder of the season. Due to the smaller loot pools and the exceptional power of raid items, these rewards will require two Nebulous Voidcores upon defeating a raid boss. Other endgame content, such as Mythic+, will cost only one. As a result, acquiring a particularly desired trinket, weapon, or ring is likely to require a similar total of Nebulous Voidcores regardless of source. For example, a player chasing a trinket from a raid boss with three total items matching their Loot Specialization is likely to receive that trinket in the same amount of time it would take to acquire a trinket from a Mythic+ dungeon with six total items." },
            { type = "p", text = "Ascendant Voidcores" },
            { type = "p", text = "Following the Voidforge’s construction, Decimus will ask players to assist him in crafting the Ascendant Nilhammer, a powerful tool capable of manipulating Ascendant Voidcores to empower worthy equipment. Upon completing this warband-wide journey, players may begin acquiring Ascendant Voidcores from Midnight Season 1 endgame content including raids, Mythic+ dungeons, Bountiful Delves, and Nightmare difficulty Prey Hunts. Consuming an Ascendant Voidcore infuses an eligible weapon or trinket with additional power to increase its item level. Only fully upgraded Hero, Myth and maximum quality Radiance Crafted weapons and trinkets are eligible to become Ascendant Voidforged." },
            { type = "image", width = 254, height = 178, u = 0.992188, v = 0.695312, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-04-22-1205-ptr-development-notes-2faa464ecf\\image-3.jpg" },
            { type = "image", width = 268, height = 201, u = 0.523438, v = 0.785156, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-04-22-1205-ptr-development-notes-2faa464ecf\\image-4.jpg" },
            { type = "image", width = 292, height = 265, u = 0.570312, v = 0.517578, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-04-22-1205-ptr-development-notes-2faa464ecf\\image-5.jpg" },
            { type = "h2", text = "DECOR DUELS(AVAILABLE IN A LATER PTR BUILD)" },
            { type = "p", text = "Amidst all the danger that swirls above Azeroth, there’s something to be said about having a little fun. Players can join in a team vs team hide-and-seek style game taking place in Silvermoon City through the Group Finder Tool (PvP tab) to either hide as various Housing decor items or seek out those who have donned the guise of an item. You’ll earn new rewards such as a mount, toys, and Housing decor through this bite-sized event." },
            { type = "h2", text = "NEW ACTIVITY: ABYSS ANGLERS" },
            { type = "p", text = "Dive deep into the shimmering waters off Zul’Aman’s rugged coast, where schools of exotic fish swarm just beneath the surface. Team up to spear as many as you can and rack up points to unlock fishing rewards and upgrades to your diver gear, allowing you to venture deeper into the abyss where the greatest treasures await." },
            { type = "p", text = "Abyss Anglers is a new repeatable event arriving just off the coast of Zul’Aman." },
            { type = "p", text = "Seek out Depthdiver Jeju to suit up and enter the Depths. Zip through whirlpools, catch creatures with your harpoon, and discover treasures amidst the underwater steam vents." },
            { type = "p", text = "Prove your mastery to earn dive equipment upgrades and cosmetics." },
            { type = "h2", text = "CLASSES" },
            { type = "dev_note", text = "With the first 12.0.5 PTR build, players will see several class changes included in this update. These are just the first round of changes; additional class changes are planned and will be added in future PTR builds over the coming weeks." },
            { type = "list_item", text = "DRACTHYR", level = 0 },
            { type = "list_item", text = "Chosen Identity", level = 1 },
            { type = "list_item", text = "Savvy spell-sleuths may notice a spell called Battle Visage in this week’s build data. While this feature isn’t ready for testing just yet, we wanted to give a heads up and set a few expectations.", level = 2 },
            { type = "list_item", text = "Battle Visage is intended to be a toggleable spell for Evokers like Chosen Identity, that while active causes your character to automatically switch to their Dracthyr form for spells that require their draconic physique. After the spell is finished, they will automatically return to Visage form.", level = 2 },
            { type = "list_item", text = "There are some technical hurdles we’re working through with Battle Visage specifically in regards to the camera positioning, as switching quickly between the forms can cause discomfort as the camera moves up and down.", level = 2 },
            { type = "list_item", text = "We look forward to your feedback on Battle Visage in a future PTR build!", level = 2 },
            { type = "list_item", text = "DEATH KNIGHT", level = 0 },
            { type = "list_item", text = "Frost", level = 1 },
            { type = "list_item", text = "Apex Talent: Chosen of Frostbrood (Rank 4) has been updated – The ability used to recall Frostwyrm’s Fury is no longer on the global cooldown.", level = 2 },
            { type = "list_item", text = "Deathbringer", level = 2 },
            { type = "list_item", text = "Echoing Fury secondary effect redesigned – Casting Reaper’s Mark grants 1 stack of Exterminate with 100% first scythe and 100% second scythe effectiveness.", level = 3 },
            { type = "list_item", text = "Exterminate has been updated – After Reaper’s Mark explodes, your next 2 Obliterates or Frostscythes cost 1 Rune and summon 2 scythes to strike the enemies. The rest of the effect remains the same.", level = 3 },
            { type = "list_item", text = "Unholy", level = 1 },
            { type = "list_item", text = "New Talent: Cycle of Death – Putrefy reduces the cooldown of Death and Decay by 1 second. Death and Decay reduces the cooldown of Putrefy by 0.3 seconds for each enemy it damages, up to 3 seconds.", level = 2 },
            { type = "list_item", text = "Raise Abomination has been updated – Disease Cloud no longer causes enemies to take increased damage from minions. Now deals Plague damage periodically to nearby enemies.", level = 2 },
            { type = "list_item", text = "Soul Reaper has been updated – No longer consumes all available charges to cast Putrefy. Instead, grants 1 charge of Putrefy when it is cast. Moved up to the 2 nd gate in the talent tree.", level = 2 },
            { type = "list_item", text = "Putrid Echoes has an additional effect – Putrefy now consumes up to 2 available charges on cast.", level = 2 },
            { type = "list_item", text = "Lesser Ghoul damage reduced by 17%.", level = 2 },
            { type = "list_item", text = "Pestilence renamed to Blightfall and now overrides Dark Transformation instead of Outbreak.", level = 2 },
            { type = "list_item", text = "Some talents have changed locations in the talent tree.", level = 2 },
            { type = "list_item", text = "The following talents have been removed:", level = 2 },
            { type = "list_item", text = "Blightfall", level = 3 },
            { type = "list_item", text = "March of Madness", level = 3 },
            { type = "list_item", text = "Scythe of Decay", level = 3 },
            { type = "list_item", text = "Rider of the Apocalypse", level = 2 },
            { type = "list_item", text = "Unholy Armaments has an additional effect – Your Ghoul and skeletal archer deal 10% and Lesser Ghouls deal 20% increased damage.", level = 3 },
            { type = "list_item", text = "A Feast of Souls has been updated – While you have 2 or more Horsemen aiding you, your Death Coil deals 20% and Epidemic deals 20% increased damage.", level = 3 },
            { type = "list_item", text = "San’layn", level = 2 },
            { type = "list_item", text = "Frenzied Bloodthirst has been updated – Essence of the Blood Queen increases the damage of your Death Coil and Death Strike by 3%, and Epidemic by 3% per stack.", level = 3 },
            { type = "list_item", text = "Thrill of Blood has an additional effect – Dread Plague deals 5% and Virulent Plague deals 5% increased damage.", level = 3 },
            { type = "list_item", text = "Desecrate has been updated – Death and Decay deals its damage 100% faster.", level = 3 },
            { type = "list_item", text = "EVOKER", level = 0 },
            { type = "list_item", text = "Blessing of the Bronze is now castable on friendly players who are not in your party or raid group, similar to other group buffs like Arcane Intellect.", level = 1 },
            { type = "list_item", text = "Augmentation", level = 1 },
            { type = "list_item", text = "New Talent: Mighty Inferno – Inferno’s Blessing’s damage is increased by 40%, and your effects that extend Ebon Might also extend Inferno’s Blessing. Replaces Molten Embers.", level = 2 },
            { type = "list_item", text = "Inferno’s Blessing will now correctly always apply to the casting Evoker, and will no longer apply to pets.", level = 2 },
            { type = "list_item", text = "Regenerative Chitin has a new icon.", level = 2 },
            { type = "list_item", text = "Molten Embers has been removed.", level = 2 },
            { type = "list_item", text = "Chronowarden", level = 2 },
            { type = "list_item", text = "New Talent: Chronal Dynamo – Living Flame’s cast time is reduced by 0.2 seconds, and it deals 50% increased damage or healing when it is a non-instant cast. Replaces Energy Cycles.", level = 3 },
            { type = "list_item", text = "Energy Cycles has been removed.", level = 3 },
            { type = "list_item", text = "Preservation", level = 2 },
            { type = "dev_note", text = "The following changes are intended to help Preservation heal spread out targets, particularly in dungeons. Temporal Anomaly is now a more reliable spell that you can fall back on to keep your party safe and Emerald Blossom now has better talent support to heal allies even if they are not stacked.", level = 3 },
            { type = "list_item", text = "Temporal Anomaly has been redesigned – Now instantly applies an absorb to your target and up to 4 allies within 40 yards, rather than being an area trigger that travels forward.", level = 3 },
            { type = "list_item", text = "Fluttering Seedlings has been redesigned slightly – Emerald Blossom sends out 1 / 2 flying seedlings when it bursts, plus up to 2 / 4 additional seedlings if Emerald Blossom heals fewer than 5 allies. Each seedling heals an ally up to 40 yards away.", level = 3 },
            { type = "list_item", text = "Fluttering Seedlings healing increased by 67%.", level = 3 },
            { type = "list_item", text = "Fluttering Seedlings is now considered a Green spell and its healing is increased by Ouroboros.", level = 3 },
            { type = "list_item", text = "Life-giver’s Flame now also functions with Deep Breath, causing the first 5 targets hit to heal nearby allies for 80% of damage done.", level = 3 },
            { type = "list_item", text = "Chronowarden", level = 3 },
            { type = "list_item", text = "New Talent: Chronal Dynamo – Living Flame’s cast time is reduced by 0.2 seconds, and it deals 50% increased damage or healing when it is a non-instant cast. Replaces Energy Cycles.", level = 4 },
            { type = "list_item", text = "Energy Cycles has been removed.", level = 4 },
            { type = "list_item", text = "HUNTER", level = 0 },
            { type = "list_item", text = "Survival", level = 1 },
            { type = "dev_note", text = "The following changes are intended to help underperforming talents and provide a damage bonus to dual-wielding Survival Hunters.", level = 2 },
            { type = "list_item", text = "Sic 'Em has been updated – Now triggers from Strike as One critical strikes (was Kill Command).", level = 2 },
            { type = "list_item", text = "Lunge has been updated – No longer grants Wildfire Bomb cooldown reduction. Now additionally grants 2% Agility, increased by an additional 2% while dual-wielding.", level = 2 },
            { type = "list_item", text = "Pack Leader", level = 2 },
            { type = "list_item", text = "Hogstrider has been redesigned – Each time your Boar deals damage, the damage of your next Boomstick is increased by 5%, up to 20%.", level = 3 },
            { type = "list_item", text = "Hoof and Blade has been redesigned – Now increases Hogstrider’s damage bonus by 2%.", level = 3 },
            { type = "list_item", text = "Sharpened Fangs has been updated – Now additionally increases the damage Wildfire Bomb deals to its primary target by 15%.", level = 3 },
            { type = "list_item", text = "Lethal Barbs now grants 1 Focus (was 2 Focus).", level = 3 },
            { type = "list_item", text = "MAGE", level = 0 },
            { type = "list_item", text = "Arcane", level = 1 },
            { type = "dev_note", text = "We’re adjusting Arcane Pulse to behave identically to Arcane Blast to reduce the decision-space around which spell should be cast at different times.", level = 2 },
            { type = "list_item", text = "Arcane Pulse cast time is now 2.25 seconds (was 1.75 seconds) and its cast time is reduced by 8% for each Arcane Charge you have.", level = 2 },
            { type = "list_item", text = "Fixed an issue where Arcane Missiles with Aether Attunement talented or an Overpowered Missiles proc would target critters and pull them into combat, but not deal damage to them.", level = 2 },
            { type = "list_item", text = "Frost", level = 1 },
            { type = "dev_note", text = "We’re making some cosmetic and clarity-related changes to Glacial Spike so that players can easily find Frostbolt in their spellbooks. We’re also adjusting the 4th rank for Hand of Frost to help make Ray of Frost feel like more of a moment and help ease the decision point on its best use-case while we also look to distribute the power of the 2nd charge elsewhere. We’ll be monitoring the throughput impact of these changes and make adjustments as necessary.", level = 2 },
            { type = "list_item", text = "Icicles has been updated – No longer generates rapidly out of combat.", level = 2 },
            { type = "list_item", text = "Glacial Spike now has a duration of 60 seconds (was unlimited).", level = 2 },
            { type = "list_item", text = "Apex Talent: Hand of Frost (Rank 4) – No longer grants an additional charge of Ray of Frost. Now causes Ray of Frost to generate 8 Hands of Frost over its duration (was 4). Ray of Frost damage increased by 30% (was 25%).", level = 2 },
            { type = "list_item", text = "MONK", level = 0 },
            { type = "list_item", text = "Windwalker", level = 1 },
            { type = "list_item", text = "Crashing Fists has been redesigned – Fists of Fury damage is increased by 20% (was extends duration by 1 second).", level = 2 },
            { type = "list_item", text = "Apex Talent: Tigereye Brew (Rank 1) has been redesigned – Every 3 Chi spent generates Tigereye Brew. Zenith consumes up to 20 Tigereye Brew stacks to increase your critical strike chance for its duration by 2% per stack. Generates quickly up to 10 stacks while out of combat and may generate up a maximum of 30 stacks.", level = 2 },
            { type = "list_item", text = "Apex Talent: Tigereye Brew (Rank 3) has been redesigned – Zenith now grants access to 2 additional Zenith Stomps.", level = 2 },
            { type = "list_item", text = "Xuen’s Battlegear may now additionally trigger from Spinning Crane Kick, reducing the cooldown of Fists of Fury by 0.5 seconds for each unique target struck, up to 2.5 seconds.", level = 2 },
            { type = "list_item", text = "Zenith Stomp now generates 2 Chi.", level = 2 },
            { type = "list_item", text = "Zenith no longer generates 2 Chi on cast.", level = 2 },
            { type = "list_item", text = "PALADIN", level = 0 },
            { type = "list_item", text = "Holy", level = 1 },
            { type = "list_item", text = "Apex Talent: Beacon of the Savior (Rank 4) now causes Flash of Light and Holy Light to move Beacon of the Savior to their target once per 5 seconds.", level = 2 },
            { type = "list_item", text = "Herald of the Sun", level = 2 },
            { type = "list_item", text = "Walk Into Light has been redesigned – Now increases the chance for Infusion of Light to occur by 100% during Avenging Wrath.", level = 3 },
            { type = "list_item", text = "Lightsmith", level = 2 },
            { type = "list_item", text = "Holy Armaments now generate 3 Holy Power.", level = 3 },
            { type = "list_item", text = "SHAMAN", level = 0 },
            { type = "list_item", text = "Enhancement", level = 1 },
            { type = "list_item", text = "To better reflect their effects, the names of Raging Maelstrom and Overflowing Maelstrom talents have been swapped.", level = 2 },
            { type = "list_item", text = "Overflowing Maelstrom secondary effect has been updated – Each Maelstrom Weapon stack consumed grants Overflowing Maelstrom, reducing the cast time and increasing the healing of your next Healing Surge or Chain Heal by 10%. Overflowing Maelstrom can accumulate up to 20 stacks, benefiting each cast by up to 10 stacks.", level = 2 },
            { type = "list_item", text = "WARRIOR", level = 0 },
            { type = "list_item", text = "Arms", level = 1 },
            { type = "list_item", text = "Mortal Wounds now triggers from Mortal Strike and Slam (was Mortal Strike and Cleave).", level = 2 },
            { type = "list_item", text = "Colossus", level = 2 },
            { type = "list_item", text = "Practiced Strikes now increases Mortal Strike and Slam damage by 15% and Cleave and Whirlwind damage by 15%.", level = 3 },
            { type = "list_item", text = "Slayer", level = 2 },
            { type = "list_item", text = "Reap the Storm now triggers when Whirlwind or Cleave hits 3 or more targets. Chance to trigger changed to 15% (was 20%).", level = 3 },
            { type = "list_item", text = "Imminent Demise no longer causes Sudden Death to trigger Reap the Storm.", level = 3 },
            { type = "list_item", text = "Unrelenting Onslaught now also increases damage dealt by Bladestorm by 20%.", level = 3 },
            { type = "list_item", text = "Fury", level = 1 },
            { type = "list_item", text = "Hack and Slash has been redesigned – Rampage has 100% chance to refund a charge of Raging Blow.", level = 2 },
            { type = "list_item", text = "Improved Whirlwind now causes Whirlwind to apply Rend to all targets if Rend is known.", level = 2 },
            { type = "list_item", text = "Slayer", level = 2 },
            { type = "list_item", text = "Reap the Storm now triggers when Whirlwind hits 3 or more targets. Chance to trigger changed to 15% (was 30%).", level = 3 },
            { type = "list_item", text = "Imminent Demise no longer causes Sudden Death to trigger Reap the Storm.", level = 3 },
            { type = "list_item", text = "Unrelenting Onslaught now increases damage dealt by Bladestorm by 20%.", level = 3 },
            { type = "list_item", text = "Protection", level = 1 },
            { type = "list_item", text = "Colossus", level = 2 },
            { type = "list_item", text = "Practiced Strikes now increases Shield Slam damage by 15% and Revenge and Thunder Clap damage by 15%.", level = 3 },
            { type = "h2", text = "HOUSING" },
            { type = "list_item", text = "If a guild member currently in the guild neighborhood is kicked or leaves the guild, they will now be teleported out of the guild neighborhood during their eviction. Their eviction notice should be visible after teleporting.", level = 0 },
            { type = "list_item", text = "HOUSE EXTERIOR EDITOR IMPROVEMENTS:", level = 0 },
            { type = "list_item", text = "Added a popup to warn about Decor attached to your House when swapping types.", level = 1 },
            { type = "list_item", text = "Added a hide/show Decor toggle while editing your House Exterior.", level = 1 },
            { type = "list_item", text = "We now prevent position and rotation from resetting when swapping exterior House types.", level = 1 },
            { type = "list_item", text = "Updated Exterior House Editor button to use a unique button icon.", level = 1 },
            { type = "list_item", text = "Implemented new budget icons for House Upgrades.", level = 0 },
            { type = "list_item", text = "You can now click Decor links in chat to open the Decor Catalog. Shift+Clicking Decor will also link it in chat.", level = 0 },
            { type = "list_item", text = "Decor and Houses now fade in, rather than simply popping in at distance.", level = 0 },
            { type = "list_item", text = "Added a friendlier message when you try to enter a House that you are not allowed in.", level = 0 },
            { type = "list_item", text = "Updated the chat message when acquiring Decor to include links to the Decor in the Catalog", level = 0 },
            { type = "list_item", text = "Your Dyed versions of the same Decor are now shown on one card instead of multiple cards in the Decor Catalog, with the ability to cycle between your owned variants in the preview window.", level = 0 },
            { type = "list_item", text = "In the Cornerstone pane, updated the confirmation dialogs for Buy and Move to include the plot number, Neighborhood, and price.", level = 0 },
            { type = "list_item", text = "Added a new tutorial helptip for how to switch Endeavors. Added a reminder in the inactive Endeavor’s page that only one Endeavor can be contributed to at a time.", level = 0 },
            { type = "list_item", text = "Added a tooltip for the Endeavors completion reward that displays the House XP and Community Coupons earned.", level = 0 },
            { type = "h2", text = "PROFESSIONS" },
            { type = "list_item", text = "Cooking and vendor refreshments now restore health and mana based on a percentage, rather than a fixed amount.", level = 0 },
            { type = "dev_note", text = "World of Warcraft offers a wide variety of food and drink items, so there are some food and drink items that are still being updated.", level = 1 },
            { type = "list_item", text = "The Deftness stat now scales at a slower rate for Dragonflight , Khaz Algar , and Midnight professions.", level = 0 },
            { type = "dev_note", text = "As a side effect of squishing stats and item levels, Deftness scaled disproportionately faster than other professions stats, making it trivial to reach 100%+ Deftness in Dragonflight and Khaz Algar professions. This change brings Deftness back in line to expected values.", level = 1 },
            { type = "h2", text = "USER INTERFACE AND ACCESSIBILITY" },
            { type = "list_item", text = "Damage Meter windows now have a minimize/maximize button, leaving only the header bar when minimized.", level = 0 },
            { type = "list_item", text = "Previously, certain features needed to be enabled in game options before being accessible in Edit Mode. Now, you can shift click the feature’s checkbox in Edit Mode to enable the feature directly. This applies to features including Cooldown Manager, Damage Meter, Boss Warnings, External Defensives, and Loot Window.", level = 0 },
            { type = "list_item", text = "The default size of raid frames and arena frames has been increased.", level = 0 },
            { type = "list_item", text = "Added the ability to invite cross faction players to a party from the Recent Allies window.", level = 0 },
            { type = "list_item", text = "There is a new icon for “stay a while and listen” NPCs.", level = 0 },
            { type = "list_item", text = "TRANSMOGRIFICATION", level = 0 },
            { type = "list_item", text = "Added a /outfit command to change outfits. Use /outfit x, with x being the outfit’s order number in the transmogrification pane. Using /outfit with no number or /outfit x with that outfit already equipped will clear all transmogs instead (use /outfit !x to avoid this behavior). Trial of Style outfit uses /outfit 0.", level = 1 },
            { type = "list_item", text = "Added a Sheathe Weapon toggle to the transmog preview pane.", level = 1 },
            { type = "list_item", text = "Two Situations have been added: Weather and Time of Day.", level = 1 },
            { type = "list_item", text = "The Sets and Custom Sets section now have a more detailed tooltip that shows the collection status of the set and its appearances.", level = 1 },
            { type = "list_item", text = "When there is an outfit discount in effect, the cost is now green with a tooltip showing the source of the discount.", level = 1 },
            { type = "list_item", text = "Added a glow to the “Save Outfit” button when there are pending changes.", level = 1 },
            { type = "list_item", text = "Fixed an issue where certain items with special visual effects, such as Forest Lord’s Antlers, would be displayed incorrectly when applied as a transmogrification.", level = 1 },
            },
        },
        ["2026-04-22-adjustments-to-reduce-non-participation-in-dungeons-8bb90b5d10"] = {
            id = "2026-04-22-adjustments-to-reduce-non-participation-in-dungeons-8bb90b5d10",
            post_key = "8bb90b5d10",
            title = "Adjustments to Reduce Non-Participation in Dungeons",
            category = "The Burning Crusade Classic (EU)",
            timestamp = 1776867641,
            url = "https://eu.forums.blizzard.com/en/wow/t/615824/1",
            content = {
            { type = "h3", text = "Update April 14, 04:15 CEST" },
            { type = "p", text = "Yesterday, we implemented the hotfixes described above to support core gameplay in instances in Burning Crusade Classic Anniversary. Unfortunately, these changes were impaired by bugs that did not appear in our pre-release testing. The result was unintended behavior of drops for both solo and group players. For example: one bug resulted in some players becoming completely disallowed from rolling on loot." },
            { type = "p", text = "With an update we sent to the live game a few minutes ago, we have reverted the original changes while we investigate these bugs." },
            { type = "p", text = "Thank you for your feedback." },
            { type = "hr" },
            { type = "p", text = "We’ve observed a significant number of Burning Crusade players entering dungeons and then participating in no meaningful gameplay, often while only one party member plays through the instance. When this is prominent, it can lead to detrimental economic effects, among other concerns, so we’re implementing a series of hotfixes to address it." },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "Dungeons", level = 0 },
            { type = "list_item", text = "Players must participate in combat to receive experience from dungeons.", level = 1 },
            { type = "list_item", text = "The amount of loot dropped by non-boss enemies in high-level dungeons is now determined by how many players participate in the kill.", level = 1 },
            { type = "p", text = "The vast majority of players who participate in dungeon groups as usual should see no difference after these updates." },
            { type = "p", text = "These changes will go into effect with scheduled weekly maintenance in each region." },
            },
        },
        ["2026-04-22-hunt-or-be-hunted-in-decor-duels-e00293fd23"] = {
            id = "2026-04-22-hunt-or-be-hunted-in-decor-duels-e00293fd23",
            post_key = "e00293fd23",
            title = "Hunt or be Hunted in Decor Duels",
            category = "Blogs (EU)",
            timestamp = 1776867636,
            url = "https://news.blizzard.com/en-gb/article/24271369/hunt-or-be-hunted-in-decor-duels",
            content = {
            { type = "p", text = "Amidst all the danger that swirls above Azeroth, there’s something to be said about having a little fun. Join in a team vs team hide-and-seek style game taking place in Silvermoon City (Midnight). Previously announced in the State of Azeroth, this fast-paced player vs. player activity puts you right in the thick of it whether you’re a harmless cheese platter or some other seemingly innocuous item." },
            { type = "p", text = "No matter your level, it’s an even playing field once the match begins." },
            { type = "p", text = "Map:Silvermoon’s Falconwing SquareLevels: 10-90Rules" },
            { type = "list_item", text = "Casual, non-lethal PvP", level = 0 },
            { type = "list_item", text = "Hiders use illusions to disguise themselves as everyday objects.", level = 0 },
            { type = "list_item", text = "Seekers use dispelling magic to break the hiders’ disguises.", level = 0 },
            { type = "list_item", text = "Get Found and Tagged, and you’re out!", level = 0 },
            { type = "p", text = "Players can queue up from anywhere using the Group Finder (Hotkey- I) under the Player vs. Player tab in Quick Match. You can also speak with Fieldweaver Amolenne in Falconwing Square in Silvermoon City." },
            { type = "p", text = "Each team takes turns either hiding or seeking and there are multiple item illusions you can start as which are chosen randomly for you. Once you’ve found your hiding spot, you won’t want to sit too long or you’ll begin to collect flies and give your position away." },
            { type = "p", text = "At the start of the match, you’ll be placed in a staging area until the match begins. Seekers will be able to choose from three different seeking types in this staging area, each with slightly different abilities allowing you to swiftly move about the map or reveal those hidden. Those who are hiding will have a short time to find their best hiding spot and get ready to evade detection." },
            { type = "hr" },
            { type = "h2", text = "ROLES AND ABILITIES" },
            { type = "h3", text = "Tag!: Tag a Hider and make them Out!" },
            { type = "h3", text = "Tag!: Tag a Hider and make them Out!" },
            { type = "h3", text = "Tag!: Tag a Hider and make them Out!" },
            { type = "p", text = "Dispelling Focus: Dispel the illusions of spellcasters in front of you over 2.5 seconds, marking the Found." },
            { type = "p", text = "Nullify Magic: Dispel illusions of spellcasters in an area in front of you, marking them Found." },
            { type = "h3", text = "Anti-Magic Arrow: Dispel the illusions of spellcasters in an area, marking them Found." },
            { type = "p", text = "Dispelling Leap: Jump to a location, dispelling the illusions of spellcasters around the area of impact." },
            { type = "h3", text = "Nullification Field: Dispel the illusion of spellcasters in an area, marking them Found." },
            { type = "p", text = "Clockwork Sentinel: Put up a Sentinel for 30 seconds that applies Found and slows within the area when entered." },
            { type = "h3", text = "Riftwalk: Teleport a short distance." },
            { type = "h3", text = "Stealth (Passive): Cannot be detected from a distance. Movement speed reduced by 30%." },
            { type = "p", text = "Hiders can swap locations with nearby items, change their item, set up traps, or place decoys to prevent themselves from being found out before the time runs out." },
            { type = "hr" },
            { type = "h2", text = "REWARDING ENDINGS" },
            { type = "p", text = "When the illusions are all lifted, players will receive their rewards depending on how well they did in the match and can earn approximately 30-35 Illusionary Coins per game." },
            { type = "p", text = "Illusionary Coin Warband Transferable An arcane currency used by some denizens of Silvermoon fond of magical games." },
            { type = "p", text = "These coins can be spent on additional items such as sin’dorei-themed Housing Decor items from the Disguised Decor Duel Vendor or mount, appearances, and toys from Gamesmaster Fleurian." },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-04-22-hunt-or-be-hunted-in-decor-duels-e00293fd23\\image-1.jpg" },
