        ["2026-04-22-power-up-with-the-voidforge-99fcc6bc23"] = {
            id = "2026-04-22-power-up-with-the-voidforge-99fcc6bc23",
            post_key = "99fcc6bc23",
            title = "Power Up With the Voidforge",
            category = "Blogs (EU)",
            timestamp = 1776867633,
            url = "https://news.blizzard.com/en-gb/article/24271858/power-up-with-the-voidforge",
            content = {
            { type = "p", text = "Help aid domanaar Decimus to build a Voidforge to begin transmuting Nebulous Voidcores, which are transmutable into empowered equipment upon defeating foes in Midnight Season 1 raids or completing Mythic+ dungeons, Bountiful Delves, and Prey Hunts on Nightmare difficulty. Once the Voidforge is constructed, you’ll also assist him in crafting the Ascendant Nilhammer to transmute Ascendant Voidcores to empower worthy equipment." },
            { type = "hr" },
            { type = "h2", text = "BUILDING THE VOIDFORGE" },
            { type = "p", text = "Meet domanaar Decimus at the Howling Ridge in Voidstorm to undertake your first quest for him, “Building the Voidforge”. You’ll need to collect Elemental Voidcore Shards from Midnight Season 1 raid bosses, Bountiful Delves, and Mythic+ dungeons to begin construction." },
            { type = "p", text = "You’ll need six Elemental Voidcores in order to complete its construction and will be able to track your progress when you visit Decimus." },
            { type = "hr" },
            { type = "h2", text = "NEBULOUS VOIDCORES" },
            { type = "p", text = "Players can use Nebulous Voidcores to more easily obtain specific equipment whether you are chasing best-in-slot items on your main character or looking to quickly gear up alternate characters later in the season." },
            { type = "p", text = "Upon defeating a Midnight Season 1 raid boss or completing a Mythic+ Dungeon, Bountiful Delve, or Prey Hunt on Nightmare difficulty, players may choose to spend their Nebulous Voidcores to receive a random item appropriate for their Loot Specialization from that activity. After receiving an item in this way, it is removed from that loot pool until all eligible items have been obtained on a per-difficulty basis." },
            { type = "p", text = "Example: Receiving the Ranger-Captain's Iridescent Insignia trinket from the Crown of the Cosmos encounter in the Voidspire on Normal difficulty will not remove it from consideration on Heroic or Mythic difficulty. The item level of Mythic+ rewards from Nebulous Voidcores is equivalent to Great Vault rewards from that Keystone level, i.e., Myth 1/6 at Keystone level +10 and above." },
            { type = "p", text = "Decimus will offer Nebulous Voidcores to the player in exchange for a choice of valuable resources including gold, Voidlight Marl, and Veteran Dawncrests. The total number of Nebulous Voidcores available to a character increases by two every week for the remainder of the season. Due to the smaller loot pools and the exceptional power of raid items, these rewards will require two Nebulous Voidcores upon defeating a raid boss. Other endgame content, such as Mythic+, will cost only one. As a result, acquiring a particularly desired trinket, weapon, or ring is likely to require a similar total of Nebulous Voidcores regardless of source. For example, a player chasing a trinket from a raid boss with three total items matching their Loot Specialization is likely to receive that trinket in the same amount of time it would take to acquire a trinket from a Mythic+ dungeon with six total items." },
            { type = "p", text = "Players can also purchase a Nebulous Voidcore from Vaultkeeper Elysa for six Thalassian Tokens of Merit. Nebulous Voidcores acquired in this way do not count against the weekly increasing cap." },
            { type = "hr" },
            { type = "h2", text = "ASCENDANT VOIDCORES" },
            { type = "p", text = "Following the Voidforge's construction, Decimus will ask players to assist him in crafting the Ascendant Nilhammer, a powerful tool capable of manipulating Ascendant Voidcores to empower worthy equipment. Upon completing this warband-wide journey, players may begin acquiring Ascendant Voidcores from Midnight Season 1 endgame content including raids, Mythic+ dungeons, Bountiful Delves, and Nightmare difficulty Prey Hunts." },
            { type = "p", text = "Consuming an Ascendant Voidcore infuses an eligible weapon or trinket with additional power to increase its item level. Only fully upgraded Hero, Myth and maximum quality Radiance Crafted weapons and trinkets are eligible to become Ascendant Voidforged." },
            { type = "hr" },
            { type = "p", text = "Domanaar Decimus may have ulterior motives, but you’ll want to take advantage of the Voidforge to enhance your adventures. Good luck and we’ll see you at the forge." },
            },
        },
        ["2026-04-22-1205-content-update-notes-7be68f6387"] = {
            id = "2026-04-22-1205-content-update-notes-7be68f6387",
            post_key = "7be68f6387",
            title = "12.0.5 Content Update Notes",
            category = "Blogs (EU)",
            timestamp = 1776867627,
            url = "https://news.blizzard.com/en-gb/article/24271855/12-0-5-content-update-notes",
            content = {
            { type = "p", text = "Engage in new activities, experience more of the story in Midnight, and earn more loot as the efforts to push back the forces of the Void and their agents continue. You’ll undertake new Void Assaults, disrupt powerful Ritual Sites, get a boost with Voidforge, group up for Decor Duels, and more." },
            { type = "h2", text = "TABLE OF CONTENTS" },
            { type = "h2", text = "NEW UPDATES ARE HIGHLIGHTED IN GOLD." },
            { type = "hr" },
            { type = "h2", text = "STAVE OFF VOID ASSAULTS" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-04-22-1205-content-update-notes-7be68f6387\\image-1.jpg" },
            { type = "p", text = "The forces of the Void are vying for position and control amongst themselves in a bid for more power. As they seek every opportunity they can, attacks begin in the Eversong Woods and Zul’Aman zones. [LEARN MORE]" },
            { type = "h3", text = "Void Strike" },
            { type = "list_item", text = "Void Strikes take part in Eversong Woods or Zul’Aman on a weekly rotation. Once completed, a new one will begin in another part of the zone and continue to rotate through the zones.", level = 0 },
            { type = "h3", text = "Void Incursion" },
            { type = "list_item", text = "These larger scenarios occur when enough Void Strikes have been completed in the zones and will take the might of many of Azeroth’s champions to defeat them.", level = 0 },
            { type = "hr" },
            { type = "h2", text = "DISRUPT RITUAL SITES" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-04-22-1205-content-update-notes-7be68f6387\\image-2.jpg" },
            { type = "p", text = "Put a stop to rituals meant to empower the ambitions of power-hungry naga and Twilight’s Blade cultists in small one to five player instances. As you take on greater challenges, you’ll be able to receive greater rewards." },
            { type = "p", text = "In Ritual Sites, you’ll choose some of the challenges you’ll face as you climb through the tiers. Players will also unlock Great Vault rewards for the World content row alongside Delves and Prey." },
            { type = "p", text = "Players will earn Field Accolades from both Void Assaults and Ritual Sites as currency they can use to purchase Champion and Heroic quality gear and rewards. [LEARN MORE]" },
            { type = "hr" },
            { type = "h2", text = "GET A LEG UP WITH THE VOIDFORGE" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-04-22-1205-content-update-notes-7be68f6387\\image-3.jpg" },
            { type = "p", text = "The Voidforge will provide new opportunities for players in Midnight to take their game further. You’ll help aid domanaar Decimus build a Voidforge to begin transmuting Nebulous Voidcores, which are transmutable into powerful equipment upon defeating powerful foes in Midnight Season 1 raids or completing Mythic+ dungeons, and Bountiful Delves and Prey Hunts on Nightmare difficulty." },
            { type = "p", text = "After unlocking the Voidforge, Decimus will require additional assistance to craft the Ascendant Nilhammer, allowing players to upgrade their weapons and trinkets to new heights by collecting Ascendant Voidcores." },
            { type = "h3", text = "Nebulous Voidcore" },
            { type = "p", text = "Players can use Nebulous Voidcores to more easily obtain specific equipment whether they're chasing best-in-slot items on their main character or looking to quickly gear up their alternate characters later in the season." },
            { type = "p", text = "Upon defeating a Midnight Season 1 raid boss or completing a Mythic+ Dungeon, Bountiful Delve, or Prey Hunt on Nightmare difficulty, players may choose to spend their Nebulous Voidcores to receive a random item appropriate for their Loot Specialization from that activity. After receiving an item in this way, it is removed from that loot pool until all eligible items have been obtained on a per-difficulty basis. For example, receiving the Ranger-Captain's Iridescent Insignia trinket from the Crown of the Cosmos encounter in the Voidspire on Normal difficulty will not remove it from consideration on Heroic or Mythic difficulty. The item level of Mythic+ rewards from Nebulous Voidcores is equivalent to Great Vault rewards from that Keystone level, i.e., Myth 1/6 at Keystone level +10 and above." },
            { type = "p", text = "Decimus will offer Nebulous Voidcores to the player in exchange for a choice of valuable resources including gold, Voidlight Marl, and Veteran Dawncrests. The total number of Nebulous Voidcores available to a character increases by two every week for the remainder of the season. Due to the smaller loot pools and the exceptional power of raid items, these rewards will require two Nebulous Voidcores upon defeating a raid boss. Other endgame content, such as Mythic+, will cost only one. As a result, acquiring a particularly desired trinket, weapon, or ring is likely to require a similar total of Nebulous Voidcores regardless of source. For example, a player chasing a trinket from a raid boss with three total items matching their Loot Specialization is likely to receive that trinket in the same amount of time it would take to acquire a trinket from a Mythic+ dungeon with six total items." },
            { type = "p", text = "Players can also purchase a Nebulous Voidcore from Vaultkeeper Elysa for six Thalassian Tokens of Merit after having completed Decimus' quests to unlock the Voidforge. Nebulous Voidcores acquired in this way do not count against the weekly increasing cap." },
            { type = "h3", text = "Ascendant Voidcore" },
            { type = "p", text = "Following the Voidforge's construction, Decimus will ask players to assist him in crafting the Ascendant Nilhammer, a powerful tool capable of manipulating Ascendant Voidcores to empower worthy equipment. Upon completing this warband-wide journey over the course of several weeks, players may begin acquiring Ascendant Voidcores from Midnight Season 1 endgame content including raids, Mythic+ dungeons, Bountiful Delves, and Nightmare difficulty Prey Hunts." },
            { type = "p", text = "Consuming an Ascendant Voidcore infuses an eligible weapon or trinket with additional power to increase its item level. Only fully upgraded Hero, Myth and maximum quality Radiance Crafted weapons and trinkets are eligible to become Ascendant Voidforged." },
            { type = "hr" },
            { type = "h2", text = "HIDE OR SEEK WITH DECOR DUELS" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-04-22-1205-content-update-notes-7be68f6387\\image-4.jpg" },
            { type = "p", text = "Amidst all the danger that swirls above Azeroth, there’s something to be said about having a little fun. Players can join in a team vs team hide-and-seek style game taking place in Silvermoon City through the Group Finder Tool (PvP tab) to either hide as various Housing decor items or seek out those who have donned the guise of an item. You’ll earn new rewards, including a mount, toys, and Housing decor, through this bite-sized event. [LEARN MORE]" },
            { type = "hr" },
            { type = "h2", text = "NEW ACTIVITY: ABYSS ANGLERS" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-04-22-1205-content-update-notes-7be68f6387\\image-5.jpg" },
            { type = "p", text = "Dive deep into the shimmering waters off Zul'Aman's rugged coast, where schools of exotic fish swarm just beneath the surface in a new repeatable event—Abyss Anglers. Team up to spear as many as you can and rack up points to unlock fishing rewards and upgrades to your diver gear, allowing you to venture deeper into the abyss where the greatest treasures await." },
            { type = "p", text = "Seek out Depthdiver Jeju to suit up and enter the Depths. Zip through whirlpools, catch creatures with your harpoon, and discover treasures amidst the underwater steam vents." },
            { type = "p", text = "Prove your mastery to earn dive equipment upgrades and cosmetics." },
            { type = "hr" },
            { type = "h2", text = "ACHIEVEMENTS" },
            { type = "list_item", text = "Fixed an issue where players who already owned the Sun Darter Hatchling pet were not receiving Mind-Seeker progress and were required to loot the pet again.", level = 0 },
            { type = "hr" },
            { type = "h2", text = "CLASSES" },
            { type = "list_item", text = "DEATH KNIGHT", level = 0 },
            { type = "list_item", text = "Frost", level = 1 },
            { type = "list_item", text = "Chosen of Frostbrood (Rank 3) has been updated – When Frostwyrm's Fury is recalled, it now grants the full Haste bonus at 50% duration instead. The ability used to recall Frostwyrm’s Fury is no longer on the global cooldown.", level = 2 },
            { type = "list_item", text = "Deathbringer", level = 2 },
            { type = "list_item", text = "Echoing Fury secondary effect has been redesigned – Casting Reaper's Mark grants 1 stack of Exterminate with 100% first scythe and 100% second scythe effectiveness.", level = 3 },
            { type = "list_item", text = "Exterminate has been updated – After Reaper's Mark explodes, your next 2 Obliterates or Frostscythes cost 1 Rune and summon 2 scythes to strike the enemies. The rest of the effect remains the same.", level = 3 },
            { type = "list_item", text = "Unholy", level = 1 },
            { type = "list_item", text = "New Talent: Cycle of Death – Putrefy reduces the cooldown of Death and Decay by 1 second. Death and Decay reduces the cooldown of Putrefy by 0.3 seconds for each enemy it damages, up to 3 seconds.", level = 2 },
            { type = "list_item", text = "Raise Abomination has been updated – Disease Cloud no longer causes enemies to take increased damage from minions. Now deals Plague damage periodically to nearby enemies.", level = 2 },
            { type = "list_item", text = "Putrid Echoes has an additional effect – Putrefy now consumes up to 2 available charges on cast.", level = 2 },
            { type = "list_item", text = "Lesser Ghoul damage reduced by 17%.", level = 2 },
            { type = "list_item", text = "Scourge Strike now applies Virulent Plague in addition to spreading it.", level = 2 },
            { type = "list_item", text = "Pestilence renamed to Blightfall and now overrides Dark Transformation instead of Outbreak.", level = 2 },
            { type = "list_item", text = "Necrotic Coil's Shadowstrike damage now prefers the primary target.", level = 2 },
            { type = "list_item", text = "Some talents have changed locations in the talent tree.", level = 2 },
            { type = "list_item", text = "The following talents have been removed:", level = 2 },
            { type = "list_item", text = "Blightfall", level = 3 },
            { type = "list_item", text = "March of Madness", level = 3 },
            { type = "list_item", text = "Scythe of Decay", level = 3 },
            { type = "list_item", text = "Rider of the Apocalypse", level = 2 },
            { type = "list_item", text = "Unholy Armaments has an additional effect – Your Ghoul and skeletal archer deal 10% and Lesser Ghouls deal 20% increased damage.", level = 3 },
            { type = "list_item", text = "A Feast of Souls has been updated – While you have 2 or more Horsemen aiding you, your Death Coil deals 20% and Epidemic deals 20% increased damage.", level = 3 },
            { type = "list_item", text = "San'layn", level = 2 },
