            { type = "list_item", text = "Colossus", level = 2 },
            { type = "list_item", text = "Practiced Strikes now increases Mortal Strike and Slam damage by 15% and Cleave and Whirlwind damage by 15%.", level = 3 },
            { type = "list_item", text = "Demolish’s area of effect strike radius increased to 10 yards (was 8 yards).", level = 3 },
            { type = "list_item", text = "Dominance of the Colossus reduces the cooldown of Demolish by 5 seconds when you would gain a stack of Colossal Might and are already at max stacks (was 2 seconds).", level = 3 },
            { type = "list_item", text = "Slayer", level = 2 },
            { type = "list_item", text = "Reap the Storm has been updated – When Cleave hits 3 or more targets you have a 20% chance to unleash a flurry of steel, striking all nearby enemies for high Physical damage and applying Overwhelmed.", level = 3 },
            { type = "list_item", text = "Unrelenting Onslaught now also increases damage dealt by Bladestorm by 20%.", level = 3 },
            { type = "list_item", text = "Fury", level = 1 },
            { type = "list_item", text = "Hack and Slash has been redesigned – Rampage has 100% chance to refund a charge of Raging Blow.", level = 2 },
            { type = "list_item", text = "Improved Whirlwind now causes Whirlwind to apply Rend to all targets if Rend is known.", level = 2 },
            { type = "list_item", text = "Slayer", level = 2 },
            { type = "list_item", text = "Reap the Storm has been updated – When Rampage hits 3 or more targets via Improved Whirlwind you have a 20% chance to unleash a flurry of steel, striking all nearby enemies for high Physical damage and applying Overwhelmed.", level = 3 },
            { type = "list_item", text = "Unrelenting Onslaught now increases damage dealt by Bladestorm by 20%.", level = 3 },
            { type = "list_item", text = "Protection", level = 1 },
            { type = "list_item", text = "Colossus", level = 2 },
            { type = "list_item", text = "Practiced Strikes now increases Shield Slam damage by 15% and Revenge and Thunder Clap damage by 15%.", level = 3 },
            { type = "list_item", text = "Demolish’s area of effect strike radius increased to 10 yards (was 8 yards).", level = 3 },
            { type = "list_item", text = "Dominance of the Colossus reduces the cooldown of Demolish by 5 seconds when you would gain a stack of Colossal Might and are already at max stacks (was 2 seconds).", level = 3 },
            { type = "hr" },
            { type = "h2", text = "DUNGEONS AND RAIDS" },
            { type = "list_item", text = "MYTHIC+", level = 0 },
            { type = "list_item", text = "New Feature: Lindormi's Glow – Lindormi's Glow highlights select enemy forces even when the Lindormi's Guidance affix is inactive. Defeating all highlighted enemies will complete the enemy forces requirement for a Keystone Dungeon.", level = 1 },
            { type = "list_item", text = "Any player whose class supports a tank role specialization can choose to use Lindormi's Glow by speaking with Lindormi near the The Timeways portal or at the end of a Keystone Dungeon.", level = 2 },
            { type = "list_item", text = "Lindormi's Glow will activate in a Keystone Dungeon if the party's tank has chosen to use this feature.", level = 2 },
            { type = "list_item", text = "Players can disable Lindormi's Glow by speaking with Lindormi again.", level = 2 },
            { type = "list_item", text = "New Achievement: Midnight Keystone Myth: Season One – Attain a Mythic+ Rating of at least 3400 during Midnight Season 1. Rewards a Timelost Saddle that can be exchanged with Lindormi for a mount of your choice. Mounts include: A variety of new mounts, and Keystone Master and Keystone Legend mounts from previous seasons.", level = 1 },
            { type = "dev_note", text = "We want to give dedicated Mythic+ players something that continues to feel rewarding over time, while also creating a path to revisit some older rewards you may have missed along the way. Keystone Myth will launch with a 3400 rating requirement, but we do not expect that threshold to remain fixed forever. Mythic+ evolves from season to season, and we want this achievement to continue to represent a similar level of difficulty and prestige each time. Because of that, we may adjust the rating requirement in future seasons.", level = 2 },
            { type = "list_item", text = "New Achievement: Umbral Champion: Midnight Season One – End Midnight Mythic+ Season 1 with a Mythic+ Rating in the top 1% of all players in your region. Rewards a new exclusive mount.", level = 1 },
            { type = "list_item", text = "Enemies will now avoid targeting stealthed players with magic bolts and abilities like Shoot.", level = 1 },
            { type = "list_item", text = "MARCH ON QUEL'DANAS", level = 0 },
            { type = "list_item", text = "Midnight Falls", level = 1 },
            { type = "list_item", text = "Dusk Crystal health reduced by 10% on Mythic difficulty.", level = 2 },
            { type = "list_item", text = "Glimmering damage reduced by 10% on Mythic difficulty.", level = 2 },
            { type = "list_item", text = "Shattered Sky damage reduced by 10% on Mythic difficulty.", level = 2 },
            { type = "list_item", text = "THE VOIDSPIRE", level = 0 },
            { type = "list_item", text = "Crown of the Cosmos", level = 1 },
            { type = "list_item", text = "Aspect of the End now pierces immunities.", level = 2 },
            { type = "list_item", text = "Gravity Collapse damage decreased by 10%.", level = 2 },
            { type = "hr" },
            { type = "h2", text = "HOUSING" },
            { type = "list_item", text = "You can now click Decor links in chat to open the Decor Catalog. Shift+Clicking Decor will also link it in chat.", level = 0 },
            { type = "list_item", text = "If a guild member currently in the guild neighborhood is kicked or leaves the guild, they will now be teleported out of the guild neighborhood during their eviction. Their eviction notice should be visible after teleporting.", level = 0 },
            { type = "list_item", text = "Implemented new budget icons for House Upgrades.", level = 0 },
            { type = "list_item", text = "Decor and Houses now fade in, rather than simply popping in at distance.", level = 0 },
            { type = "list_item", text = "Added a friendlier message when you try to enter a House that you are not allowed in.", level = 0 },
            { type = "list_item", text = "Updated the chat message when acquiring Decor to include links to the Decor in the Catalog", level = 0 },
            { type = "list_item", text = "Your Dyed versions of the same Decor are now shown on one card instead of multiple cards in the Decor Catalog, with the ability to cycle between your owned variants in the preview window.", level = 0 },
            { type = "list_item", text = "In the Cornerstone pane, updated the confirmation dialogs for Buy and Move to include the plot number, Neighborhood, and price.", level = 0 },
            { type = "list_item", text = "Added a new tutorial helptip for how to switch Endeavors. Added a reminder in the inactive Endeavor's page that only one Endeavor can be contributed to at a time.", level = 0 },
            { type = "list_item", text = "Added a tooltip for the Endeavors completion reward that displays the House XP and Community Coupons earned.", level = 0 },
            { type = "list_item", text = "Added 'Inspect Decor' option to the Housing UI.", level = 0 },
            { type = "list_item", text = "Use 'Inspect' to hover over Decor - either in your house or someone else's - to view the Decor name and view it in the Decor Catalog.", level = 1 },
            { type = "list_item", text = "HOUSE EXTERIOR EDITOR IMPROVEMENTS:", level = 0 },
            { type = "list_item", text = "Added a popup to warn about Decor attached to your House when swapping types.", level = 1 },
            { type = "list_item", text = "Added a hide/show Decor toggle while editing your House Exterior.", level = 1 },
            { type = "list_item", text = "We now prevent position and rotation from resetting when swapping exterior House types.", level = 1 },
            { type = "list_item", text = "Updated Exterior House Editor button to use a unique button icon.", level = 1 },
            { type = "hr" },
            { type = "h2", text = "ITEMS" },
            { type = "list_item", text = "Fixed an issue where Gloom-Spattered Dreadscale absorb shield value could be incorrectly calculated when damaging multiple enemies.", level = 0 },
            { type = "hr" },
            { type = "h2", text = "PLAYER VERSUS PLAYER" },
            { type = "list_item", text = "MONK", level = 0 },
            { type = "list_item", text = "Mistweaver", level = 1 },
            { type = "list_item", text = "Mana Tea now restores 50% less mana in PvP combat.", level = 2 },
            { type = "list_item", text = "Life Cocoon's absorb amount reduced by 25% in PvP combat.", level = 2 },
            { type = "list_item", text = "Chrysalis reduces the cooldown of Life Cocoon by 30 seconds in PvP combat (was 45 seconds).", level = 2 },
            { type = "list_item", text = "Zen Spheres can now be applied by Rising Sun Kick and Rushing Wind Kick.", level = 2 },
            { type = "hr" },
            { type = "h2", text = "PROFESSIONS" },
            { type = "list_item", text = "Cooking and vendor refreshments now restore health and mana based on a percentage, rather than a fixed amount.", level = 0 },
            { type = "list_item", text = "The Deftness stat now scales at a slower rate for Dragonflight , Khaz Algar , and Midnight professions.", level = 0 },
            { type = "dev_note", text = "As a side effect of squishing stats and item levels, Deftness scaled disproportionately faster than other professions stats, making it trivial to reach 100%+ Deftness in Dragonflight and Khaz Algar professions. This change brings Deftness back in line to expected values.", level = 1 },
            { type = "list_item", text = "​ Added 1 Fused Vitality to Professions Weekly Quests.", level = 0 },
            { type = "hr" },
            { type = "h2", text = "USER INTERFACE AND ACCESSIBILITY" },
            { type = "list_item", text = "Now you can shift click a feature's checkbox in Edit Mode to enable the feature directly. This applies to features including Cooldown Manager, Damage Meter, Boss Warnings, External Defensives, and Loot Window.", level = 0 },
            { type = "list_item", text = "The default size of raid frames and arena frames has been increased.", level = 0 },
            { type = "list_item", text = "Added a slider to change the size of the Big Defensive icon on raid frames.", level = 0 },
            { type = "list_item", text = "Added the ability to invite cross faction players to a party from the Recent Allies window.", level = 0 },
            { type = "list_item", text = "Damage Meter windows now have a minimize/maximize button, leaving only the header bar when minimized.", level = 0 },
            { type = "list_item", text = "There is a new icon for \"stay a while and listen\" NPCs.", level = 0 },
            { type = "list_item", text = "Fixed an issue where the Boss Timeline was shown for encounters with no timeline events.", level = 0 },
            { type = "list_item", text = "Fixed an issue that could disrupt auto-loot functionality in some situations.", level = 0 },
            { type = "list_item", text = "TRANSMOGRIFICATION", level = 0 },
            { type = "list_item", text = "New weapon sheathing options have been added, including an option to hide weapons when sheathed.", level = 1 },
            { type = "list_item", text = "Added a Sheathe Weapon toggle to the transmog preview pane.", level = 1 },
            { type = "list_item", text = "Added a /outfit command to change outfits. Use /outfit x, with x being the outfit's order number in the transmogrification pane. Using /outfit with no number or /outfit x with that outfit already equipped will clear all transmogs instead (use /outfit !x to avoid this behavior). Trial of Style outfit uses /outfit 0.", level = 1 },
            { type = "list_item", text = "Two Situations have been added: Weather and Time of Day.", level = 1 },
            { type = "list_item", text = "The Sets and Custom Sets section now have a more detailed tooltip that shows the collection status of the set and its appearances.", level = 1 },
            { type = "list_item", text = "When there is an outfit discount in effect, the cost is now green with a tooltip showing the source of the discount.", level = 1 },
            { type = "list_item", text = "Added a glow to the \"Save Outfit\" button when there are pending changes.", level = 1 },
            { type = "list_item", text = "Fixed an issue where certain items with special visual effects, such as Forest Lord's Antlers, would be displayed incorrectly when applied as a transmogrification.", level = 1 },
            { type = "hr" },
            { type = "p", text = "To view all content update notes, click here." },
            { type = "p", text = "For World of Warcraft customer support, please visit our Support Site or our Customer Support discussion forum. If you’ve found a bug, please let us know about it in our Bug Report Forum." },
            { type = "p", text = "Back to Top" },
            },
        },
        ["2026-04-22-twitch-drop-get-the-cuddly-pearl-grrgle-housing-decor-item-23-april-1a7474ef13"] = {
            id = "2026-04-22-twitch-drop-get-the-cuddly-pearl-grrgle-housing-decor-item-23-april-1a7474ef13",
            post_key = "1a7474ef13",
            title = "Twitch Drop: Get the Cuddly Pearl Grrgle Housing Decor Item 23 April!",
            category = "Blogs (EU)",
            timestamp = 1776867623,
            url = "https://news.blizzard.com/en-gb/article/24266872/twitch-drop-get-the-cuddly-pearl-grrgle-housing-decor-item-23-april",
            content = {
            { type = "p", text = "Watch any eligible World of Warcraft stream on Twitch.tv from 23 April at 23:00 BST until 21 May at 23:00 BST to claim the Cuddly Pearl Grrgle Housing decor item." },
            { type = "hr" },
            { type = "h3", text = "Eligibility" },
            { type = "p", text = "To participate, you must link your Twitch account by visiting https://account.battle.net/connections. If you have changed your password or made any changes to your Twitch or Battle.net account, you will have to relink your accounts. When you relink, there will be a 7-day cooldown before you can relink a new Twitch account. After you’ve claimed your rewards on Twitch, please make sure you’re logging into the Battle.net region you’d like to receive the drop(s) on, as the first region you log into will be where your items will be delivered. It can take up to 24 hours to receive your reward(s) in-game after claiming. Read our Frequently Asked Questions section for more information." },
            { type = "hr" },
            { type = "h3", text = "How do I Earn Twitch Drops?" },
            { type = "p", text = "Start Time: 23 April 23:00 BSTEnd Time: 21 May 23:00 BST" },
            { type = "p", text = "Watch 4 hours of eligible World of Warcraft content while these Twitch Drops are active on any channel to earn the Cuddly Pearl Grrgle Housing decor item." },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-04-22-twitch-drop-get-the-cuddly-pearl-grrgle-housing-decor-item-23-april-1a7474ef13\\image-1.jpg" },
            { type = "p", text = "Players who have claimed this new item from the Twitch Drop will also be able to visit Dennia Silvertongue in Silvermoon City to purchase more copies of this adorable item. Additional copies can also be purchased from Tuuran in Stormwind and Gabbi in Orgrimmar (near the Trading Post)." },
            { type = "hr" },
            { type = "h3", text = "Frequently Asked Questions" },
            { type = "p", text = "Q. How do I link my battle.net and Twitch accounts? A. Sign into your Battle.net account at https://account.battle.net/connections and click the Connect link for Twitch, then follow the instructions to sign in and link your Twitch account to Battle.net." },
            { type = "p", text = "Q. What devices can I use to earn and claim drops? A. You can earn and claim drops using your PC/Mac web browser or on the Twitch app for Android or iOS. Twitch apps on game consoles, smart TVs, and other TV apps do not support drops." },
            { type = "p", text = "Q. Do I need to watch the same channel the entire time to earn my drops? A. You can earn progress towards a drop on any eligible channel in the World of Warcraft category on Twitch. You can, for example, watch half an hour on one channel and then switch to another channel without losing your progress. You cannot earn progress faster by watching more than one channel at a time." },
            { type = "p", text = "Q. Will I receive my drop rewards in-game automatically? A. To receive your rewards, you must claim the drop on the channel you’re watching or in the Drops Inventory menu on Twitch." },
            { type = "p", text = "Q. Do Twitch Drop rewards expire? A. Earned Twitch Drop rewards will expire seven (7) days after they’ve been claimed if a Battle.net account has not been linked." },
            { type = "p", text = "Q. As a streamer, how do I get Twitch Drops on my channel? A. All you need to do is ensure your Twitch and Battle.net accounts are linked and that you’ve opted into Drops (see Drops Streamer Home)." },
            { type = "p", text = "Q. What regions are eligible for these Twitch Drops? A. Participating regions include North America, Latin America, Europe, The Middle East, Africa, Japan, Taiwan, Southeast Asia, Australia, and New Zealand." },
            { type = "hr" },
            { type = "p", text = "Blizzard has the right to change, pause, or cancel this Twitch Drop and its terms if it cannot run as planned for any reason, including but not limited to technical issues or unexpected factors beyond Blizzard’s control." },
            { type = "p", text = "*Not available in World of Warcraft Classic® games. Requires World of Warcraft® Subscription or Game Time. Use and placement of decor items is limited to the Housing feature, which requires access to World of Warcraft®: Midnight." },
            },
        },
        ["2026-04-22-wow-weekly-midnight-1205-classic-anniversary-edition-joyous-journeys-a-a2216bcf80"] = {
            id = "2026-04-22-wow-weekly-midnight-1205-classic-anniversary-edition-joyous-journeys-a-a2216bcf80",
            post_key = "a2216bcf80",
            title = "WoW Weekly: Midnight 12.0.5, Classic Anniversary Edition, Joyous Journeys, and More!",
            category = "Blogs (EU)",
            timestamp = 1776867619,
            url = "https://news.blizzard.com/en-gb/article/24272610/wow-weekly-midnight-12-0-5-classic-anniversary-edition-joyous-journeys-and-more",
            content = {
            { type = "p", text = "Get ready to flex your muscle in Midnight as the efforts to push back against the Void continue on 22 April with the 12.0.5 content update, the Overlords of Outland content update is on the horizon for Burning Crusade Classic Anniversary Edition, Joyous Journeys comes to Mists of Pandaria Classic, and more." },
            { type = "p", text = "Each week meets you with adventurous discovery and fresh rewards—be sure to check in to learn more about what awaits you in Azeroth." },
            { type = "hr" },
            { type = "h3", text = "The 12.0.5 Content Update Goes Live 22 April" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-04-22-wow-weekly-midnight-1205-classic-anniversary-edition-joyous-journeys-a-a2216bcf80\\image-1.jpg" },
            { type = "p", text = "Engage in new activities, experience more of the story in Midnight, and earn more loot as the efforts to push back the forces of the Void and their agents continue." },
            { type = "p", text = "You’ll undertake new Void Assaults, disrupt powerful Ritual Sites, get a boost with Voidforge, group up for Decor Duels, and more." },
            { type = "p", text = "Learn about all these features, and more, when you read through our content update overview." },
            { type = "hr" },
            { type = "h3", text = "Face New Challenges and Disrupt Ritual Sites in 12.0.5" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-04-22-wow-weekly-midnight-1205-classic-anniversary-edition-joyous-journeys-a-a2216bcf80\\image-2.jpg" },
            { type = "p", text = "Whether you’re going it solo, or gathering allies to join you, a new challenge awaits at the Ritual Sites in Eversong Woods and Zul’Aman. You’ll put a stop to rituals of power-hungry naga and Twilight’s Blade cultists in small one-to-five-player instances and face new challenges for new rewards." },
            { type = "p", text = "Ritual Sites introduce new repeatable instanced content similar to Delves, designed for flexible group sizes and allowing one to five players. Each offers escalating challenges in a bid for the heroes of the Alliance and Horde to disrupt the rituals of the naga in Eversong Woods or the Twilight’s Blade cultists in Zul’Aman." },
            { type = "p", text = "As with Delves and Prey, players will unlock Great Vault rewards in the World content row. Only you can determine what challenges you’ll undertake and which rewards you’ll choose to claim as your own. Ritual Sites are available in the 12.0.5 content update, and you can learn more about them in our previously published article." },
            { type = "hr" },
            { type = "h3", text = "Mobilize Your Allies and Thwart Incoming Void Assaults" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-04-22-wow-weekly-midnight-1205-classic-anniversary-edition-joyous-journeys-a-a2216bcf80\\image-3.jpg" },
            { type = "p", text = "The forces of the Void are vying for position and control amongst themselves in a grasp for more power. As they seek every opportunity they can, attacks begin in the Eversong Woods and Zul’Aman zones." },
            { type = "p", text = "In the 12.0.5 content update, players can push back against the Void as they begin powerful Void Strikes and Void Incursions in Eversong Woods and Zul’Aman— for Azeroth, for fun, and for new rewards. Everything you need to know can be found in our Void Assaults overview." },
            { type = "hr" },
            { type = "h3", text = "Power Up with the Voidforge" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-04-22-wow-weekly-midnight-1205-classic-anniversary-edition-joyous-journeys-a-a2216bcf80\\image-4.jpg" },
            { type = "p", text = "Help aid domanaar Decimus to build a Voidforge to begin transmuting Nebulous Voidcores, which are transmutable into empowered equipment upon defeating foes in Midnight Season 1 raids or completing Mythic+ dungeons, Bountiful Delves, and Prey Hunts on Nightmare difficulty. Once the Voidforge is constructed, you’ll also assist him in crafting the Ascendant Nilhammer to transmute Ascendant Voidcores to empower worthy equipment." },
            { type = "p", text = "Domanaar Decimus may have ulterior motives, but you’ll want to take advantage of the Voidforge to enhance your adventures. Unearth the details in our previously published article." },
            { type = "hr" },
            { type = "h3", text = "Hunt or be Hunted in Decor Duels" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-04-22-wow-weekly-midnight-1205-classic-anniversary-edition-joyous-journeys-a-a2216bcf80\\image-5.jpg" },
            { type = "p", text = "Lift your spirits and take a break from all the serious threats the Void and their agents present with a little team vs team hide-and-seek in the 12.0.5 content update. Don the guise of a random Decor Item or seek them out in this fast-paced duel for fun—and some new rewards." },
            { type = "p", text = "Amidst all the danger that swirls above Azeroth, there’s something to be said about having a little fun. Join in a team vs team hide-and-seek style game taking place in Silvermoon City (Midnight). Previously announced in the State of Azeroth, this fast-paced player vs. player activity puts you right in the thick of it whether you’re a harmless cheese platter or some other seemingly innocuous item." },
            { type = "p", text = "No matter your level, it’s an even playing field once the match begins in this 5v5 matchup." },
            { type = "p", text = "You might not defeat the Void and save Azeroth by taking part in this event, but it’s a great way to find a bit of fun in the face of danger. Learn more from our overview, and maybe we’ll see you…or maybe not… in Decor Duels." },
            { type = "hr" },
            { type = "h3", text = "WoW BCC Anniversary Edition: Overlords of Outland Arrives 14 May" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-04-22-wow-weekly-midnight-1205-classic-anniversary-edition-joyous-journeys-a-a2216bcf80\\image-6.jpg" },
            { type = "p", text = "The battle for Outland heats up on 14 May as WoW Burning Crusade Classic Anniversary Edition: Overlords of Outland launches globally on all realms at 23:00 BST." },
            { type = "p", text = "Take the fight to Illidan Stormrage’s lieutenants, brave two new raids, and chase new rewards across the shattered world of Outland." },
            { type = "list_item", text = "Two New Raids : The Eye and Serpentshrine Cavern", level = 0 },
            { type = "list_item", text = "New Reputation Factions : Ogri’la and Sha’tari Skyguard", level = 0 },
            { type = "list_item", text = "Arena Season 2", level = 0 },
            { type = "list_item", text = "New Profession Recipes", level = 0 },
            { type = "list_item", text = "Druid Swift Flight Form", level = 0 },
            { type = "p", text = "Get ready to adventure across the shattered skies and torn lands of Outland as you continue to protect Azeroth from the threat of destruction, beginning 14 May." },
            { type = "hr" },
            { type = "h3", text = "Mists of Pandaria Classic: Expect Joyous Journeys Beginning 21 April" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-04-22-wow-weekly-midnight-1205-classic-anniversary-edition-joyous-journeys-a-a2216bcf80\\image-7.jpg" },
            { type = "p", text = "Stalwart champions in World of Warcraft: Mists of Pandaria Classic, take advantage of the Joyous Journeys experience buff to enhance your odyssey through Azeroth, increasing experience gains by 50% up to level 90!" },
            { type = "p", text = "Duration: 21 April until the next content update for Mists of Pandaria Classic arrives." },
            { type = "p", text = "The mystical lands of Pandaria are swirling with danger and need your help. Create a new character, finish leveling a forgotten one, or invite friends to join you in legendary Pandaria." },
            { type = "p", text = "The Joyous Journeys buff is active by default; however, you can visit any innkeeper in the capital cities and Dalaran to turn it on or off. The Joyous Journeys buff is not available in modern World of Warcraft® (currently Midnight), World of Warcraft®: Burning Crusade Classic Anniversary Edition, or World of Warcraft® ClassicEra." },
            { type = "p", text = "See you in Pandaria!" },
            { type = "hr" },
            { type = "h3", text = "Twitch Drop: Get the Cuddly Pearl Grrgle Housing Decor Item 23 April!" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-04-22-wow-weekly-midnight-1205-classic-anniversary-edition-joyous-journeys-a-a2216bcf80\\image-8.jpg" },
            { type = "p", text = "Get the Cuddly Pearl Grrgle Housing decor item starting 23 April! Players who have claimed this new item from the Twitch Drop will also be able to visit Dennia Silvertongue in Silvermoon City to purchase more copies of this adorable decor. Additional copies can also be purchased from Tuuran in Stormwind and Gabbi in Orgrimmar (near the Trading Post)." },
            { type = "p", text = "Start Time: 23 April, 23:00 BSTEnd Time: 21 May, 323:00 BST" },
            { type = "p", text = "Watch 4 hours of any World of Warcraft content stream on Twitch.tv while these Twitch Drops are active to claim the Cuddly Pearl Grrgle Housing decor item." },
            { type = "p", text = "Frequently asked questions and details on how to link your Twitch account can be found in our previously published article." },
            { type = "hr" },
            { type = "h3", text = "Check out the World of Warcraft: Midnight Art Blast" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-04-22-wow-weekly-midnight-1205-classic-anniversary-edition-joyous-journeys-a-a2216bcf80\\image-9.jpg" },
            { type = "p", text = "Join us in celebrating the artists whose efforts helped build the visually stunning World of Warcraft®: Midnight™ in the Blizzard Entertainment World of Warcraft: Midnight Art Blast." },
            { type = "p", text = "Adventure is calling you home in World of Warcraft: Midnight, where you’ll return to the re-envisioned elven kingdom of Quel’Thalas and adventure through new and reimagined zones in the battle between the Light and the Void as Xal’atath’s invasion of Azeroth grows stronger, and the Voidstorm threatens to cover the world in darkness." },
            { type = "p", text = "Midnight is now live, and your hour has come—take up arms and embark on all-new stories, zones, and dungeons, and put down roots of your own with Housing." },
            { type = "p", text = "Prepare to answer the call—learn more." },
            { type = "hr" },
            { type = "p", text = "Follow along as you get ready for new challenges and can’t-miss moments in-game. Whenever news drops, find it on the World of Warcraft news site, along with announcements, highlights, and what to tackle next." },
            },
        },
        ["2026-04-22-hotfixes-april-17-2026-9ec3c4d322"] = {
            id = "2026-04-22-hotfixes-april-17-2026-9ec3c4d322",
            post_key = "9ec3c4d322",
            title = "Hotfixes: April 17, 2026",
            category = "Blogs (EU)",
            timestamp = 1776867616,
            url = "https://news.blizzard.com/en-gb/article/24266320/hotfixes-april-14-2026",
            content = {
            { type = "p", text = "Here you'll find a list of hotfixes that address various issues related to World of Warcraft: Midnight, Mists of Pandaria Classic, Season of Discovery, Burning Crusade Classic, WoW Classic Era, and Hardcore. Some of the hotfixes below take effect the moment they were implemented, while others may require scheduled realm restarts to go into effect. Please keep in mind that some issues cannot be addressed without a client-side patch update. This list will be updated as additional hotfixes are applied." },
            { type = "h2", text = "HOTFIXES" },
            { type = "hr" },
            { type = "h3", text = "April 17, 2026" },
            { type = "h3", text = "Delves" },
            { type = "list_item", text = "Reaching Midnight Season 1 Delver's Journey Rank 10 will now properly reward the Void Breacher title.", level = 0 },
            { type = "h3", text = "Dungeons and Raids" },
            { type = "list_item", text = "Maisara Caverns", level = 0 },
            { type = "list_item", text = "Rak'tul", level = 1 },
            { type = "list_item", text = "Spectral Residue duration increased to 40 seconds.", level = 2 },
            { type = "list_item", text = "Additional applications of Spectral Residue no longer refresh the duration.", level = 2 },
            { type = "list_item", text = "Seat of the Triumvirate", level = 0 },
            { type = "list_item", text = "Addressed an issue where Merciless Subjugator's Chains of Subjugation can be interrupted unintentionally.", level = 1 },
            { type = "list_item", text = "The Voidspire", level = 0 },
            { type = "list_item", text = "Fallen-King Salhadaar", level = 1 },
            { type = "list_item", text = "Fixed an issue where Void Infusion could override the boss entering berserk phase.", level = 2 },
            { type = "list_item", text = "Lightblinded Vanguard", level = 1 },
            { type = "list_item", text = "Addressed an issue where using the raid skip can fail to spawn all three paladins for the encounter.", level = 2 },
            { type = "hr" },
            { type = "h3", text = "April 14, 2026" },
            { type = "h3", text = "Dungeons and Raids" },
            { type = "list_item", text = "Maisara Caverns", level = 0 },
            { type = "list_item", text = "Frenzied Berserker’s health reduced by 13%.", level = 1 },
            { type = "list_item", text = "Keen Headhunter’s health reduced by 10%.", level = 1 },
            { type = "list_item", text = "Muro'jin and Nekraxx", level = 1 },
            { type = "list_item", text = "Resolved an issue where Carrion Swoop could occasionally strike units behind Nekraxx or strike players twice.", level = 2 },
            { type = "list_item", text = "Seat of the Triumvirate", level = 0 },
            { type = "list_item", text = "Addressed an issue where some area of the dungeon is unintentionally empowering creatures.", level = 1 },
            { type = "list_item", text = "Siphon Void in L’ura’s encounter is now marked as important.", level = 1 },
