            { type = "list_item", text = "Skyreach", level = 0 },
            { type = "list_item", text = "Target of Cast Down now has a debuff on their unit frame.", level = 1 },
            { type = "list_item", text = "Windrunner Spire", level = 0 },
            { type = "list_item", text = "Commander Kroluk", level = 1 },
            { type = "list_item", text = "Fixed an issue where Commander Kroluk could fail his jump based on his target's location within his chamber.", level = 2 },
            { type = "list_item", text = "The Voidspire", level = 0 },
            { type = "list_item", text = "Vaelgor & Ezzorak", level = 1 },
            { type = "list_item", text = "Resolved an issue where Ezzorak could continue to fight the Lightbound Vanguard after Vaelgor and all players have perished.", level = 2 },
            { type = "list_item", text = "Lightblinded Vanguard", level = 1 },
            { type = "list_item", text = "War Chaplain Senn's Aura of Peace silence effect no longer triggers from Halo, Ice Lance, or Galactic Guardian Moonfire.", level = 2 },
            { type = "list_item", text = "Resolved an issue where Execution Sentence's vulnerability could sometimes not work in Mythic difficulty.", level = 2 },
            { type = "list_item", text = "Health reduced by 5% on Mythic difficulty.", level = 2 },
            { type = "dev_note", text = "Our goal with this change is to encourage a greater diversity of raid compositions to succeed in the encounter.", level = 3 },
            { type = "list_item", text = "Crown of the Cosmos", level = 1 },
            { type = "list_item", text = "Alleria and Rift Simulacrum's health reduced by 5% in Heroic difficulty.", level = 2 },
            { type = "list_item", text = "Cosmic Barrier absorb amount reduced by 5% in Heroic difficulty.", level = 2 },
            { type = "list_item", text = "Silverstrike Ricochet width increased to 5 yards in non-Mythic difficulties (was 4 yards).", level = 2 },
            { type = "list_item", text = "Undying Voidspawn's nearby player detection range has been reduced to 10 yards in non-Mythic difficulties (was 15 yards).", level = 2 },
            { type = "list_item", text = "March on Quel’danas", level = 0 },
            { type = "list_item", text = "L’ura’s health reduced by 5% on Mythic difficulty.", level = 1 },
            { type = "list_item", text = "Termination Matrix", level = 1 },
            { type = "list_item", text = "Terminate applications reduced to 4 (was 5).", level = 2 },
            { type = "list_item", text = "Terminate cast time increased to 2 seconds (was 1.5 seconds).", level = 2 },
            { type = "list_item", text = "Heaven’s Glaives", level = 1 },
            { type = "list_item", text = "Blades per cast reduced to 5 on Heroic and Mythic difficulties (was 6).", level = 2 },
            { type = "list_item", text = "Max duration reduced to 2 minutes on Heroic and Mythic difficulties (was 3 minutes).", level = 2 },
            { type = "list_item", text = "Grim Symphony", level = 1 },
            { type = "list_item", text = "Melody can no longer repeat the same Dark Rune twice.", level = 2 },
            { type = "list_item", text = "Second cast now spins clockwise (was counter-clockwise).", level = 2 },
            { type = "list_item", text = "Eclipsed heal absorb reduced by 10% on Mythic difficulty.", level = 2 },
            { type = "list_item", text = "Overkill Current damage reduced by 20% on Heroic difficulty.", level = 2 },
            { type = "list_item", text = "The final cast of Criticality now triggers 2 Tears of L’ura per Dawn Crystal (was 3).", level = 2 },
            { type = "list_item", text = "Dark Constellation precast time increased to 2.5 seconds on Mythic difficulty (was 2 seconds).", level = 2 },
            { type = "h3", text = "Quests" },
            { type = "list_item", text = "Fixed a bug where players were unable to collect handfuls of sand from Loosened Sand piles in Vol'dun for \"The Fragrance of the Dunes\".", level = 0 },
            { type = "hr" },
            { type = "h3", text = "April 13, 2026" },
            { type = "h3", text = "Classes" },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Fixed an issue causing Bestial Wrath to not deal damage if Bestial Wrath's charge would put the Pet out of range.", level = 1 },
            { type = "h3", text = "Dungeons and Raids" },
            { type = "list_item", text = "Algeth’ar Academy", level = 0 },
            { type = "list_item", text = "Addressed an issue where Crawth's Deafening Screech's debuff could persist after the encounter ended.", level = 1 },
            { type = "list_item", text = "Addressed an issue where Alpha Eagle could start casting Gust while still in the air.", level = 1 },
            { type = "list_item", text = "Maisara Caverns", level = 0 },
            { type = "list_item", text = "Resolved an issue causing Hollow Soulrender's Frost Nova to occasionally inflict damage at the incorrect location.", level = 1 },
            { type = "list_item", text = "Pit of Saron", level = 0 },
            { type = "list_item", text = "Forgemaster Garfrost", level = 1 },
            { type = "list_item", text = "Fixed an issue that could prevent Night Elf Vengeance Demon Hunters from being able to hide behind Saronite Ore.", level = 2 },
            { type = "list_item", text = "March on Quel'danas", level = 0 },
            { type = "list_item", text = "Belo'ren, Child of Al'ar", level = 1 },
            { type = "list_item", text = "Belo'ren's Stage Two health has been reduced by 10% on Mythic difficulty.", level = 2 },
            { type = "list_item", text = "Ashen Benediction has been reduced to 5% per stack on all difficulties (was 10%).", level = 2 },
            { type = "list_item", text = "Reduced the frequency of Guardian's Edict casts over the course of the encounter on all difficulties.", level = 2 },
            { type = "list_item", text = "The Voidspire", level = 0 },
            { type = "list_item", text = "Corrected an issue where the Lightblinded Vanguard could fail to appear after using the raid skip.", level = 1 },
            { type = "list_item", text = "Vaelgor & Ezzorak", level = 1 },
            { type = "list_item", text = "Addressed an issue where the bosses could respawn atop the Devouring Stronghold instead of their arena.", level = 2 },
            { type = "h3", text = "Items" },
            { type = "list_item", text = "Light's Preservation potion now provides more healing.", level = 0 },
            { type = "hr" },
            { type = "h3", text = "April 9, 2026" },
            { type = "h3", text = "Classes" },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Beast Mastery", level = 1 },
            { type = "list_item", text = "Corrected an issue where the Wild Instincts talent could cause more damage than intended when fighting a single target.", level = 2 },
            { type = "list_item", text = "Priest", level = 0 },
            { type = "list_item", text = "Discipline", level = 1 },
            { type = "list_item", text = "Oracle: Fixed an issue where Blaze of Light would not apply its slow effect on enemies.", level = 2 },
            { type = "list_item", text = "Holy", level = 1 },
            { type = "list_item", text = "Oracle: Fixed an issue causing Preemptive Care to increase the duration of Renews from Lasting Words by 25%, instead of the intended 40%.", level = 2 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Demonology", level = 1 },
            { type = "list_item", text = "Fixed an issue where demons summoned by Dominion of Argus would not prioritize your target.", level = 2 },
            { type = "list_item", text = "Diabolist: Fixed an issue where Diabolist demons would not prioritize your target.", level = 2 },
            { type = "list_item", text = "Diabolist: Overlord, Mother of Chaos, and Pit Lord should no longer be summoned when Diabolic Art is removed if their summoner is not in combat.", level = 2 },
            { type = "h3", text = "Delves" },
            { type = "list_item", text = "Valeera now speaks less frequently in Delves.", level = 0 },
            { type = "h3", text = "Dungeons and Raids" },
            { type = "list_item", text = "Magisters' Terrace", level = 0 },
            { type = "list_item", text = "Fixed a rare issue where it was possible for non-boss enemies to fail to spawn correctly.", level = 1 },
            { type = "list_item", text = "The Dreamrift", level = 0 },
            { type = "list_item", text = "Chimaerus the Undreamt God", level = 1 },
            { type = "list_item", text = "Resolved an issue where Chimaerus could become stuck in the environment.", level = 2 },
            { type = "list_item", text = "The Voidspire", level = 0 },
            { type = "list_item", text = "Crown of the Cosmos", level = 1 },
            { type = "list_item", text = "The second target of Grasp of Emptiness in Mythic difficulty will now prefer non-healer specialized characters.", level = 2 },
            { type = "h3", text = "Horrific Visions" },
            { type = "list_item", text = "Fixed a bug where completion credit for Oblivion Elemental in Vision of Orgimmar was not granted if the player killed it too quickly.", level = 0 },
            { type = "h3", text = "Quests" },
            { type = "list_item", text = "\"Midnight: Legends of the Haranir\" is no longer among the weekly activity choice selection options.", level = 0 },
            { type = "dev_note", text = "“Legends of the Haranir” quests are only completable once weekly per Warband, but this weekly activity was available to all characters. This change resolves a case where players who already completed their weekly Legends of the Haranir quest on one character would be prevented from completing the weekly activity on an alt.", level = 1 },
            { type = "hr" },
            { type = "h3", text = "April 7, 2026" },
            { type = "h3", text = "Classes" },
            { type = "list_item", text = "Death Knight", level = 0 },
            { type = "list_item", text = "Blood", level = 1 },
            { type = "list_item", text = "Melee auto-attack damage increased by 25%.", level = 2 },
            { type = "list_item", text = "Death Strike damage increased by 12%.", level = 2 },
            { type = "list_item", text = "Blood Fortification armor increased to 45% (was 35%).", level = 2 },
            { type = "list_item", text = "Bone Shield now increases armor by 180% of Strength (was 150%).", level = 2 },
            { type = "list_item", text = "Frost", level = 1 },
            { type = "dev_note", text = "Frost Death Knight is behind our expectations in single target damage, so we’re increasing Obliterate and Frost Strike damage to give a more targeted boost in single target scenarios, along with a damage increase to Frostbane to help Rider of the Apocalypse in multi-target scenarios.", level = 2 },
            { type = "list_item", text = "Obliterate damage increased by 12%. Not applied to PvP combat.", level = 2 },
            { type = "list_item", text = "Frost Strike and Frostbane damage increased by 15%. Not applied to PvP combat.", level = 2 },
            { type = "list_item", text = "Unholy", level = 1 },
            { type = "list_item", text = "Resolved an issue causing the tier set aura Blighted to interfere with Nazgrim's Conquest value increases.", level = 2 },
            { type = "list_item", text = "Demon Hunter", level = 0 },
            { type = "list_item", text = "Vengeance", level = 1 },
            { type = "dev_note", text = "Vengeance single target damage has remained below expectations, so single target damage sources are being increased.", level = 2 },
            { type = "list_item", text = "Melee auto-attack damage increased by 40%.", level = 2 },
            { type = "list_item", text = "Focused Cleave damage bonus for Soul Cleave’s primary target increased to 60% (was 50%).", level = 2 },
            { type = "list_item", text = "Soul Carver damage increased by 50%.", level = 2 },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "Balance", level = 1 },
            { type = "list_item", text = "Starfall damage increased by 16%. Not applied to PvP combat.", level = 2 },
            { type = "list_item", text = "Ascendant Eclipses’ Lunar Bolt damage increased by 10%. Not applied to PvP combat.", level = 2 },
            { type = "list_item", text = "Guardian", level = 1 },
            { type = "list_item", text = "Scintillating Moonlight now causes Moonfire to reduce damage dealt to you by 6%/12% (was 5%/10%).", level = 2 },
            { type = "list_item", text = "Rend and Tear now causes Thrash to reduce the target’s damage done to you by 3% per stack (was 2%).", level = 2 },
            { type = "list_item", text = "Evoker", level = 0 },
            { type = "list_item", text = "Augmentation", level = 1 },
            { type = "list_item", text = "Ebon Might's radius for applying to allies increased to 500 yds (was 100 yds).", level = 2 },
            { type = "list_item", text = "Devastation", level = 1 },
            { type = "dev_note", text = "Flameshaper’s performance in single target scenarios is less competitive with Scalecommander than desired. This adjustment is intended to increase Flameshaper’s viability, without invalidating the time and effort Evokers have put into learning how to play Scalecommander effectively.", level = 2 },
            { type = "list_item", text = "Flameshaper: Consume Flame now causes Disintegrate to detonate 150% of Fire Breath damage (was 115%).", level = 2 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "Holy", level = 1 },
            { type = "dev_note", text = "Holy Paladins healing output is behind our expectations, so we’re targeting an increase to their holy power spenders to reinforce their core gameplay loop and make using resources more satisfying.", level = 2 },
            { type = "list_item", text = "Word of Glory healing increased by 20%. This also applies to Eternal Flame and its periodic healing.", level = 2 },
            { type = "list_item", text = "Light of Dawn healing increased by 20%.", level = 2 },
            { type = "list_item", text = "Protection", level = 1 },
            { type = "dev_note", text = "We’re observing that Protection Paladins are experiencing difficulty with magical damage and periodic damage in Mythic+ dungeons. Our intent with these adjustments is to improve survivability and agency with a combination of upfront damage reduction and self-healing.", level = 2 },
            { type = "list_item", text = "Auto-attack damage increased by 50%. Not applied to PvP combat.", level = 2 },
            { type = "list_item", text = "Glory of the Vanguard (Rank 2/Rank 3) increases Judgment damage by 20%/40% (was 10%/20%). Not applied to PvP combat.", level = 2 },
            { type = "list_item", text = "Glory of the Vanguard (Rank 4) increases Shield of the Righteous’ damage to your primary target by 100% (was 50%). Not applied to PvP combat.", level = 2 },
            { type = "list_item", text = "Greater Judgment causes the target to take 50% increased damage from your next Shield of the Righteous (was 40%). Not applied to PvP combat.", level = 2 },
            { type = "list_item", text = "Imbued Shield reduces magical damage taken by 12% (was 10%).", level = 2 },
            { type = "list_item", text = "Redoubt increases armor by up to 60% based on missing health (was 50%).", level = 2 },
            { type = "list_item", text = "Light of the Titans’ healing is increased by 200% when afflicted by a harmful periodic effect (was 100%).", level = 2 },
            { type = "list_item", text = "Monk", level = 0 },
            { type = "list_item", text = "Brewmaster", level = 1 },
            { type = "dev_note", text = "Moving into Midnight, Brewmasters gained a significant amount of self-healing. While this has shored up one of the spec’s longstanding weaknesses, we’re finding the total of their defensive capability is a bit too potent. These changes aim to tone down self-healing and narrow the gap between Monks and other tank specializations.", level = 2 },
            { type = "list_item", text = "Vital Flame now causes you to heal for 40% of all Fire or Nature damage dealt by your spells and abilities (was 50%).", level = 2 },
            { type = "list_item", text = "Shado-Pan: Predictive Training now reduces all damage taken by 8% (was 10%).", level = 2 },
            { type = "list_item", text = "Windwalker", level = 1 },
            { type = "list_item", text = "Fists of Fury now deals 60% of its primary target damage to other targets (was 54%).", level = 2 },
            { type = "list_item", text = "Rogue", level = 0 },
            { type = "list_item", text = "Assassination", level = 1 },
            { type = "list_item", text = "Caustic Spatter causes 20% of your Nature damage to hit nearby enemies (was 18%).", level = 2 },
            { type = "list_item", text = "Garrote and Rupture damage increased by 5%.", level = 2 },
            { type = "list_item", text = "Fan of Knives and Crimson Tempest damage increased by 10%.", level = 2 },
            { type = "list_item", text = "Outlaw", level = 1 },
            { type = "list_item", text = "All damage increased by 4%.", level = 2 },
            { type = "list_item", text = "Blade Flurry causes your abilities to strike nearby enemies for 28% of damage dealt (was 30%).", level = 2 },
            { type = "list_item", text = "Fatebound: Fate Intertwined increases the percent of damage Blade Flurry spreads by 5 (was 6).", level = 2 },
            { type = "list_item", text = "Trickster: Nimble Flurry increases Blade Flurry damage by 25% while Flawless Form is active (was 30%).", level = 2 },
            { type = "list_item", text = "Shaman", level = 0 },
            { type = "list_item", text = "Enhancement", level = 1 },
            { type = "dev_note", text = "We are making some adjustments for Enhancement that are aimed at helping consistent damage sources outside of burst windows, while slightly skewed towards bringing Stormbringer’s performance closer to Totemic.", level = 2 },
            { type = "list_item", text = "Lightning Bolt damage increased by 8%. Not applied to PvP combat.", level = 2 },
            { type = "list_item", text = "Chain Lightning damage increased by 25%. Not applied to PvP combat.", level = 2 },
            { type = "list_item", text = "Crash Lightning initial impact damage increased by 20%. Not applied to PvP combat.", level = 2 },
            { type = "list_item", text = "Crash Lightning weapon enhancement effect damage increased by 10%. Not applied to PvP combat.", level = 2 },
            { type = "list_item", text = "Stormstrike and Windstrike damage increased by 15%. Not applied to PvP combat.", level = 2 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Fixed an issue where Infernal Beneficiary would not heal for the intended amount if Drain Life was specifically used on Delve enemies.", level = 1 },
            { type = "list_item", text = "Demonology", level = 1 },
            { type = "list_item", text = "Fixed an issue where Demonic Knowledge could activate more than intended.", level = 2 },
            { type = "list_item", text = "Fixed an issue where Demonic Brutality increased critical damage dealt by pets by 260%, rather than the intended 230%.", level = 2 },
            { type = "h3", text = "Delves" },
            { type = "list_item", text = "Consecrated Chalice stacks of Hope will no longer fall off outside of combat.", level = 0 },
            { type = "list_item", text = "Fixed an issue that could sometimes cause Valeera to take increased damage in Gulf of Memory.", level = 0 },
            { type = "h3", text = "Dungeons and Raids" },
            { type = "list_item", text = "Magisters’ Terrace", level = 0 },
            { type = "list_item", text = "Addressed an issue in Degentrius' encounter where there can be multiple instances of Unstable Void Essence active.", level = 1 },
            { type = "list_item", text = "Addressed an issue where enemies on the way to Seranel Sunlash can fail to spawn in Mythic+ if Arcanotron Custos is defeated in Mythic in the same instance.", level = 1 },
            { type = "list_item", text = "Nexus-Point Xenas", level = 0 },
