            { type = "list_item", text = "Players falling off the platform during the Rukhran encounter will now be teleported back to the platform.", level = 1 },
            { type = "list_item", text = "March on Quel'danas", level = 0 },
            { type = "list_item", text = "Belo'ren, Child of Al'ar", level = 1 },
            { type = "list_item", text = "Belo’ren’s stage one health reduced by 10% on Mythic difficulty.", level = 2 },
            { type = "list_item", text = "Infused Quills now targets fewer players over the course of the encounter on Mythic difficulty.", level = 2 },
