            { type = "list_item", text = "Lightblinded Vanguard", level = 1 },
            { type = "list_item", text = "Avenger's Shield now targets 4 players on Mythic difficulty (was 8).", level = 2 },
            { type = "list_item", text = "Tyr's Wrath healing absorb decreased by 17% on Mythic difficulty.", level = 2 },
            { type = "list_item", text = "Sacred Toll damage reduced by 15% on Mythic difficulty.", level = 2 },
            { type = "list_item", text = "Crown of the Cosmos", level = 1 },
            { type = "list_item", text = "Resolved an issue where Void Expulsion could be placed at Alleria's location without a player present.", level = 2 },
            { type = "list_item", text = "Resolved an issue where two Ranger Captain's Marks could sometimes pick the same player on Mythic difficulty.", level = 2 },
            { type = "list_item", text = "Resolved an issue where Grasp of Emptiness could be spell reflected.", level = 2 },
            { type = "h3", text = "Items" },
            { type = "list_item", text = "Crucible of Erratic Energies Leech reduced by 50%.", level = 0 },
            { type = "list_item", text = "Light of the Cosmic Crescendo healing increased by 35%.", level = 0 },
            { type = "list_item", text = "Shadow of the Empyrean Requiem damage increased by 20%.", level = 0 },
            { type = "list_item", text = "Whisper of the Duskwraith healing increased by 35%.", level = 0 },
            { type = "list_item", text = "Echo of L'ura healing increased by 35%.", level = 0 },
            { type = "list_item", text = "Radiant Sunstone initial healing increased by 35%.", level = 0 },
            { type = "list_item", text = "The following housing decor items are now Bind to Warband: Rutaani Sporepod, Rustic Harandar Planter, Grand Aethercharged Crystal, and Kafa Press.", level = 0 },
            { type = "list_item", text = "The Postmaster has mailed the missing Chimaerus and Crown of the Cosmos encounter trophy decor to eligible characters.", level = 0 },
            { type = "list_item", text = "Fixed an issue where some players were unable to consume Gleaming Sunmote to unlock alternate armor appearances.", level = 0 },
            { type = "list_item", text = "Fixed an issue preventing alternate shoulder armor appearances for Druids from being unlocked.", level = 0 },
            { type = "h3", text = "Player versus Player" },
            { type = "list_item", text = "Resolved an issue that prevented Honor earned in Slayer's Rise to count towards progress in the “Enshrouded in War” quest.", level = 0 },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "Restoration", level = 1 },
            { type = "dev_note", text = "A substantial buff is needed to help Restoration, who have been struggling to keep up in healing throughput as well as defensively.", level = 2 },
            { type = "list_item", text = "All healing increased by 8% in PvP combat.", level = 2 },
            { type = "list_item", text = "Regrowth healing increased by 40% in PvP combat.", level = 2 },
            { type = "list_item", text = "Swiftmend healing increased by 25% in PvP combat.", level = 2 },
            { type = "list_item", text = "Barkskin now reduced damage taken by 30% in PvP combat (was 20%).", level = 2 },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Marksmanship", level = 1 },
            { type = "dev_note", text = "Marksmanship is a burst outlier, so we’re reducing the power of Aimed Shot and increasing sustained damage from other primary damage sources to keep it feeling powerful, while reducing the peaks of its burst.", level = 2 },
            { type = "list_item", text = "Aimed Shot damage reduced by 10% in PvP combat.", level = 2 },
            { type = "list_item", text = "Kill Shot and Black Arrow damage increased by 15% in PvP combat.", level = 2 },
            { type = "list_item", text = "Rapid Fire damage increased by 15% in PvP combat.", level = 2 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "Arcane", level = 1 },
            { type = "dev_note", text = "Arcanosphere damage has fallen behind other sources in Midnight. We’re also buffing Sunfury in all gameplay (above) to make it more competitive with Spellslinger.", level = 2 },
            { type = "list_item", text = "Arcanosphere damage increased by 250%.", level = 2 },
            { type = "list_item", text = "Fire", level = 1 },
            { type = "dev_note", text = "Fire Mage has strong burst during Combustion which has gotten a bit too strong. We’re aiming to reduce power in this window by adjusting talents that are propping up damage during Combustion and otherwise are looking to keep sustained damage in a similar state.", level = 2 },
            { type = "list_item", text = "Each stack of Fired Up now increases Fire damage by 2% in PvP combat (was 4%).", level = 2 },
            { type = "list_item", text = "Burn It All now increases spell damage by 5% during Combustion in PvP combat (was 10%).", level = 2 },
            { type = "list_item", text = "Monk", level = 0 },
            { type = "list_item", text = "Mistweaver", level = 1 },
            { type = "dev_note", text = "Mistweavers have continued to be a step above other healers this season, with strong sustained healing in addition to having strong cooldowns more frequently than other healers. These adjustments target some of those cooldowns.", level = 2 },
            { type = "list_item", text = "All healing reduced by 4% in PvP combat.", level = 2 },
            { type = "list_item", text = "Conduit of the Celestials: Heart of the Jade Serpent now causes Thunder Focus Tea to increase the recovery rate of Renewing Mist, Rising Sun Kick, Life Cocoon, and Thunder Focus Tea by 30% for 8 seconds in PvP combat (was 75%).", level = 2 },
            { type = "list_item", text = "Conduit of the Celestials: Celestial Conduit healing reduced by 50% in PvP combat.", level = 2 },
            { type = "list_item", text = "Windwalker", level = 1 },
            { type = "dev_note", text = "We feel that Windwalkers’ burst windows are too difficult to react to, so we’re reducing the damage of Zenith Stomp and Rushing Wind Kick while adding some damage to Fists of Fury, which has felt less impactful this season. Additionally, it’s not uncommon to die through Touch of Karma, so we’re increasing the amount of damage it absorbs, to increase its effectiveness as a survival tool.", level = 2 },
            { type = "list_item", text = "Zenith Stomp damage reduced by 25% in PvP combat.", level = 2 },
            { type = "list_item", text = "Rushing Wind Kick damage reduced by 15% in PvP combat.", level = 2 },
            { type = "list_item", text = "Fists of Fury damage increased by 15% in PvP combat.", level = 2 },
            { type = "list_item", text = "Touch of Karma now absorbs 20% more damage in PvP combat.", level = 2 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "dev_note", text = "We’re looking to reduce burst damage to targets at low health for all Paladin specializations, which is mainly caused by Vengeful Wrath. Additionally, Blessing of Spellwarding has been a powerful spell since it was introduced with few counters and works against most specializations which can feel oppressive to play against. We’re reducing its duration in PvP so that it can remain a powerful defensive.", level = 1 },
            { type = "list_item", text = "Vengeful Wrath now increases Hammer of Wrath damage by up to 20% based on the target’s health (was 50%).", level = 1 },
            { type = "list_item", text = "Blessing of Spellwarding duration reduced to 6 seconds in PvP combat (was 10 seconds).", level = 1 },
            { type = "list_item", text = "Holy", level = 1 },
            { type = "dev_note", text = "After recent tuning and the general Paladin changes here, Holy is in a good spot. This increase of the power of a major source of healing from Herald of the Sun should shore up the viability of the hero tree.", level = 2 },
            { type = "list_item", text = "Herald of the Sun: Eternal Flame healing increased by 20% in PvP combat.", level = 2 },
            { type = "list_item", text = "Protection", level = 1 },
            { type = "list_item", text = "All damage reduced by 10% in PvP combat.", level = 2 },
            { type = "list_item", text = "Retribution", level = 1 },
            { type = "dev_note", text = "We’re looking to add more punch to finishers from Ret which have felt weak this season, so we’re increasing the damage of Final Verdict to achieve that. We’re also increasing the damage of Dawnlight to increase the viability of the Herald of the Sun hero talents.", level = 2 },
            { type = "list_item", text = "Templar’s Verdict and Final Verdict damage increased by 25% in PvP combat.", level = 2 },
            { type = "list_item", text = "Herald of the Sun: Dawnlight damage increased by 30% in PvP combat.", level = 2 },
            { type = "list_item", text = "Rogue", level = 0 },
            { type = "list_item", text = "Subtlety", level = 1 },
            { type = "dev_note", text = "Subtlety has continued to be a strong asset to a team, with its frequent burst and strong crowd control. We’re bringing down some of its potential burst with these changes to keep their power level more in line relative to their overall kit.", level = 2 },
            { type = "list_item", text = "Death Perception effects now increase finisher damage by 3% each in PvP combat (was 5%).", level = 2 },
            { type = "list_item", text = "Replicating Shadows bonus damage for Shadow Clones reduced to 5% in PvP combat (was 15%).", level = 2 },
            { type = "list_item", text = "Shaman", level = 0 },
            { type = "dev_note", text = "We’re increasing the damage of some Shaman PvP talents that have fallen behind other sources of damage. We’d like Lightning Lasso to feel worth fully channeling and trying to interrupt and for Electrocute to be a noticeable effect when Purging enemies.", level = 1 },
            { type = "list_item", text = "Lightning Lasso damage increased by 450%.", level = 1 },
            { type = "list_item", text = "Electrocute damage increased by 35%.", level = 1 },
            { type = "list_item", text = "Elemental", level = 1 },
            { type = "list_item", text = "Farseer: All Ancestor healing increased by 20% in PvP combat.", level = 2 },
            { type = "list_item", text = "Enhancement", level = 1 },
            { type = "dev_note", text = "We feel Enhancement is in a good place after last week’s tuning. Enhancement has outlier burst potential with Tempest, so we’re toning down, so that it’s easier to react to its burst.", level = 2 },
            { type = "list_item", text = "Stormbringer: Tempest damage reduced by 15% in PvP combat.", level = 2 },
            { type = "list_item", text = "Restoration", level = 1 },
            { type = "dev_note", text = "We’re targeting a buff to Farseer this week. Its healing has fallen behind, and we’re aiming to increase its viability compared to Totemic.", level = 2 },
            { type = "list_item", text = "Farseer: All Ancestor healing increased by 20% in PvP combat.", level = 2 },
            { type = "list_item", text = "Farseer: Elemental Reverb now increases Riptide healing by 25% in PvP combat (was 10%).", level = 2 },
            { type = "list_item", text = "Warrior", level = 0 },
            { type = "list_item", text = "Arms", level = 1 },
            { type = "dev_note", text = "Arms can sometimes struggle to connect, so we’re making a change to Battle Stance to help with mobility against slow and root effects. Additionally, we’re increasing the power of Ignore Pain so that it feels more worthwhile to use when trying to survive.", level = 2 },
            { type = "list_item", text = "Battle Stance now reduces the duration of movement impairment effects by 25% in PvP combat (was 10%).", level = 2 },
            { type = "list_item", text = "Ignore Pain absorption increased by 20% in PvP combat.", level = 2 },
            { type = "list_item", text = "Fury", level = 1 },
            { type = "dev_note", text = "Damage is in a good state for Mountain Thane, but there is some potential for burst from Bloodthirst that we’re looking to reign in. We’re also increasing the damage from Execute to increase the viability of the Slayer hero talents.", level = 2 },
            { type = "list_item", text = "Execute damage increased by 20% in PvP combat.", level = 2 },
            { type = "list_item", text = "Mountain Thane: Burst of Power now increases the damage of Bloodthirst by 15% (was 35%).", level = 2 },
            { type = "h3", text = "Prey" },
            { type = "list_item", text = "Creatures summoned by Prey traps will now correctly clear Bloody Command on death.", level = 0 },
            { type = "h3", text = "Professions" },
            { type = "list_item", text = "Gems will now be found more regularly when prospecting Midnight ore.", level = 0 },
            { type = "list_item", text = "Fixed an issue where Recipe: Vicious Thalassian Flask of Honor was Bind on Pickup.", level = 0 },
