            { type = "list_item", text = "Fixed a bug where Avenger's Shield was targeting pets.", level = 2 },
            { type = "list_item", text = "Resolved an issue where gaining an additional stack of Tyr's Wrath would refresh the absorb value to its maximum value for each stack.", level = 2 },
