            { type = "list_item", text = "Fixed an issue where abandoning “One by One”, “Intercepted”, or “Keys Are Optional” could permanently prevent Valeera from appearing, blocking progression on “The Crimson Rogue” questline.", level = 0 },
            { type = "list_item", text = "Resolved an issue where Risen Witherbark did not provide credit for \"The Crypt in the Mist.\"", level = 0 },
            { type = "list_item", text = "Players above level 80 should now be able to access the scenario \"A Light in the Dark\" while on the quest of the same name.", level = 0 },
