            { type = "list_item", text = "Players who were unable to access the Hunt Table in Astalor's Sanctum after completing a Prey quest should once again be able to accept new hunts, as long as they haven’t completed the 4 weekly hunt maximum.", level = 0 },
            { type = "dev_note", text = "There is currently a display bug for those who were affected by the previous issue that may show they have 1 more hunt available than they actually do. This will be fixed with weekly restarts.", level = 1 },
            { type = "h3", text = "Quests" },
            { type = "list_item", text = "Creatures in the Midnight introduction that takes you to the Isle of Quel'Danas now have lower health and deal less damage.", level = 0 },
            { type = "list_item", text = "Players should be able to continue handing out fliers to folks during \"Mobilize! Enlist! Recruit!” if they leave and then come back to their task.", level = 0 },
            { type = "list_item", text = "Fixed an issue where Rage-Riddled Drifter would take a long time to respawn for “Overcoming the Unknown” world quest.", level = 0 },
            { type = "h3", text = "User Interface and Accessibility" },
            { type = "list_item", text = "To ensure that macro usage aligns with our overall goals for addons, there have been some minor changes made to macro capabilities:", level = 0 },
            { type = "list_item", text = "Macros are prevented from setting a target marker on more than 3 units within a very short time.", level = 1 },
            { type = "list_item", text = "And the following restrictions only apply while the player is in an active encounter:", level = 0 },
            { type = "list_item", text = "Macros are no longer allowed to send chat messages to chat channels that are not exclusive to the group (custom chat channels, guild, communities, etc).", level = 1 },
            { type = "list_item", text = "Macros are still allowed to send chat in group-exclusive channels (/raid, /party, /rw, etc), but are prevented from sending multiple messages to those channels within a very short time. In addition, all members of the group must be inside the instance or macro chat will not be allowed in these channels.", level = 1 },
            { type = "list_item", text = "Macros are still allowed to send chat in whispers but the whisper target must also be in the instance. Macros are also prevented from sending multiple whispers within a very short time.", level = 1 },
