            { type = "h3", text = "Dungeons and Raids" },
            { type = "list_item", text = "Den of Nalorakk", level = 0 },
            { type = "list_item", text = "Resolved an issue that could result in Nalorakk becoming unattackable.", level = 1 },
            { type = "list_item", text = "Magisters’ Terrace", level = 0 },
            { type = "list_item", text = "Completing the Magisters' Terrace dungeon at any difficulty will now complete the quest “Magisters' Terrace: Homecoming”, even if the player has not completed the first objective to speak with Umbric.", level = 1 },
            { type = "h3", text = "Items" },
            { type = "list_item", text = "Fixed a bug causing some Bind-on-Equip items from Midnight content to require a player level lower than intended for the item level of the gear.", level = 0 },
            { type = "list_item", text = "Resolved an issue causing some items from Midnight content that were equipped by players to be temporarily unusable.", level = 0 },
            { type = "list_item", text = "Items that unintentionally cost 750 Voidlight Marl now cost 25 Marl.", level = 0 },
            { type = "list_item", text = "Fixed a bug that could cause War Supply Crate to spawn underground in Eversong Woods.", level = 0 },
            { type = "h3", text = "Professions" },
            { type = "list_item", text = "To account for the acquisition of Knowledge in Early Access, two weeks’ worth of Knowledge will be granted to players from activities (Crafting Orders, treasure drops, Patron Orders, gathering) during the first full week of Midnight (March 3-10).", level = 0 },
            { type = "h3", text = "Quests" },
            { type = "list_item", text = "Fixed an issue with the Void Beast in \"The Line Must Be Drawn Here\" sometimes being unkillable, blocking quest progress.", level = 0 },
            { type = "list_item", text = "Fixed a bug preventing progress on “Wrath Unleashed”. Players who are stuck on this quest can now abandon and retry the quest to proceed with the story.", level = 0 },
            { type = "list_item", text = "Players who leave before completing the \"Ethereal Eradication\" or \"Light's Arsenal\" quests should now be able to resume them.", level = 0 },
