            { type = "list_item", text = "Priest", level = 0 },
            { type = "list_item", text = "Shadow", level = 1 },
            { type = "dev_note", text = "Shadow Word: Death has been lacking in damage, even in execute range, so we’re significantly increasing its damage to correct this. To increase damage in multi-target situations, we’re targeting some AoE-only sources and shifting some power from some single target sources of damage to Shadowy Apparition damage.", level = 2 },
            { type = "list_item", text = "Shadow Word: Death damage increased by 80%.", level = 2 },
            { type = "list_item", text = "Mind Blast and Void Blast damage reduced by 10%.", level = 2 },
            { type = "list_item", text = "Shadow Apparition and Void Apparition damage increased by 35%.", level = 2 },
            { type = "list_item", text = "Spectral Horrors now increases Shadowy Apparition damage against targets affected by Shadow Word: Madness by 30% (was 50%).", level = 2 },
            { type = "list_item", text = "Psychic Link causes direct damage spells to inflicts 25% of their damage on all targets afflicted by Vampiric Touch (was 20%).", level = 2 },
            { type = "list_item", text = "Void Spike from Things from Beyond now deals 25% additional damage to secondary targets.", level = 2 },
