            { type = "list_item", text = "Fixed an issue where the chance to generate a Demonic Core from a Wild Imp fading was lower than the intended amount.", level = 2 },
            { type = "list_item", text = "Fixed an issue where Antoran Jailer would stop attacking enemies if they fly.", level = 2 },
