            { type = "list_item", text = "The Voidspire", level = 0 },
            { type = "list_item", text = "The portal after the Crown of the Cosmos encounter now takes you outside of the raid instance.", level = 1 },
            { type = "list_item", text = "Fallen King Salhadaar", level = 1 },
            { type = "list_item", text = "Shadow Fracture cast time increased to 12 seconds on Mythic difficulty (was 9 seconds).", level = 2 },
            { type = "list_item", text = "Fractured Projections will now gain Broken Shield when their Shadow Fracture spell can be interrupted on Mythic difficulty.", level = 2 },
            { type = "list_item", text = "Lightblinded Vanguard", level = 1 },
