        ["2026-04-22-mists-of-pandaria-classic-joyous-journeys-is-now-live-4958717bae"] = {
            id = "2026-04-22-mists-of-pandaria-classic-joyous-journeys-is-now-live-4958717bae",
            post_key = "4958717bae",
            title = "Mists of Pandaria Classic: Joyous Journeys is Now Live",
            category = "Blogs (EU)",
            timestamp = 1776867603,
            url = "https://news.blizzard.com/en-gb/article/24272609/mists-of-pandaria-classic-joyous-journeys-is-now-live",
            content = {
            { type = "p", text = "Stalwart champions in World of Warcraft: Mists of Pandaria Classic, take advantage of the Joyous Journeys experience buff to enhance your odyssey through Azeroth, increasing experience gains by 50% up to level 90!" },
            { type = "p", text = "Duration: 21 April until the next content update for Mists of Pandaria Classic arrives." },
            { type = "p", text = "The mystical lands of Pandaria are swirling with danger and need your help. Create a new character, finish leveling a forgotten one, or invite friends to join you in legendary Pandaria." },
            { type = "p", text = "The Joyous Journeys buff is active by default; however, you can visit any innkeeper in the capital cities and Dalaran to turn it on or off. The Joyous Journeys buff is not available in modern World of Warcraft® (currently Midnight), World of Warcraft®: Burning Crusade Classic Anniversary Edition, or World of Warcraft® ClassicEra." },
            { type = "hr" },
            { type = "p", text = "See you in Pandaria!" },
            },
        },
